static RUNTIME: LazyLock<Runtime> = LazyLock::new(|| {
    Builder::new_multi_thread()
        .worker_threads(4)
        .enable_all()
        .build()
        .expect("Failed to create Tokio runtime")
});

fn runtime() -> PyResult<&'static Runtime> {
    // Access the LazyLock; if the builder panicked, this will propagate.
    // In normal operation the expect above fires only if thread/memory
    // limits are exhausted, which is unrecoverable anyway.  Wrapping
    // the *access* lets Python callers see a catchable exception when
    // a previous panic poisoned the LazyLock.
    std::panic::catch_unwind(|| &*RUNTIME)
        .map_err(|_| pyo3::exceptions::PyRuntimeError::new_err("Failed to create Tokio runtime"))
}

/// Consume a Python `logging.LogRecord` and emit a Rust `tracing::Event` instead.
///
/// Emits synchronously on the calling thread (no async needed since there are
/// no `.await` points) and uses `Span::in_scope()` instead of `span.enter()`
/// to avoid holding an `Entered` guard across thread boundaries.
#[pyfunction]
fn host_log<'py>(record: Bound<'py, PyAny>) -> PyResult<()> {
    let level = record.getattr("levelno")?.extract::<u8>()?;
    let message = record.getattr("getMessage")?.call0()?.to_string();
    let pathname = record.getattr("pathname")?.to_string();
    let lineno = record.getattr("lineno")?.extract::<u32>().unwrap_or(0);
    let target = record.getattr("name")?.to_string();

    if level >= 40 {
        span!(Level::ERROR, "dora.python.log.error", file = pathname, line = lineno, %target, %message)
            .in_scope(|| tracing::event!(tracing::Level::ERROR, file = pathname, line = lineno, %target, %message));
    } else if level >= 30 {
        span!(Level::WARN, "dora.python.log.warn", file = pathname, line = lineno, %target, %message)
            .in_scope(|| tracing::event!(tracing::Level::WARN, file = pathname, line = lineno, %target, %message));
    } else if level >= 20 {
        span!(Level::INFO, "dora.python.log.info", file = pathname, line = lineno, %target, %message)
            .in_scope(|| tracing::event!(tracing::Level::INFO, file = pathname, line = lineno, %target, %message));
    } else if level >= 10 {
        span!(Level::DEBUG, "dora.python.log.debug", file = pathname, line = lineno, %target, %message)
            .in_scope(|| tracing::event!(tracing::Level::DEBUG, file = pathname, line = lineno, %target, %message));
    } else {
        span!(Level::TRACE, "dora.python.log.trace", file = pathname, line = lineno, %target, %message)
            .in_scope(|| tracing::event!(tracing::Level::TRACE, file = pathname, line = lineno, %target, %message));
    }
    Ok(())
}

/// Modifies the Python `logging` module to deliver its log messages to the host `tracing::Subscriber` by default.
/// To achieve this goal, the following changes are made to the module:
/// - A new builtin function `logging.host_log` transcodes `logging.LogRecord`s to `tracing::Event`s. This function
///   is not exported in `logging.__all__`, as it is not intended to be called directly.
/// - A new class `logging.HostHandler` provides a `logging.Handler` that delivers all records to `host_log`.
/// - `logging.basicConfig` is changed to use `logging.HostHandler` by default.
///
/// Since any call like `logging.warn(...)` sets up logging via `logging.basicConfig`, all log messages are now
/// delivered to `crate::host_log`, which will send them to `tracing::event!`.
pub fn setup_logging(py: Python) -> PyResult<()> {
    let logging = py.import("logging")?;
    // `setup_logging` runs on every `Node` construction. Installing the
    // `basicConfig` wrapper a second time would wrap the wrapper (the new
    // `oldBasicConfig` would be the first wrapper), so every `basicConfig`
    // call would attach one `HostHandler` per `Node` ever created in this
    // process and emit duplicate log records. `oldBasicConfig` only exists
    // once the wrapper is installed, so use it as the install marker.
    if logging.hasattr("oldBasicConfig")? {
        return Ok(());
    }
    logging.setattr("host_log", wrap_pyfunction!(host_log, &logging)?)?;
    py.run(
        cr#"
class HostHandler(Handler):
	def __init__(self, level=0):
		super().__init__(level=level)
	
	def emit(self, record):
		host_log(record)

oldBasicConfig = basicConfig

def basicConfig(*pargs, **kwargs):
	if "handlers" not in kwargs:
		kwargs["handlers"] = [HostHandler()]
	else:
		kwargs["handlers"].append(HostHandler())
	if "level" not in kwargs:
		kwargs["level"] = 0

	return oldBasicConfig(*pargs, **kwargs)
"#,
        Some(&logging.dict()),
        None,
    )?;

    let all = logging.index()?;
    all.append("HostHandler")?;

    Ok(())
}

/// Pre-compiled CUDA DMA helper module. Compiled once (at first use) and reused
/// across all iterations to eliminate per-call PyModule::from_code overhead.
/// Maintains persistent state: pinned host pointers, pre-allocated GPU buffers.
static CUDA_HELPERS: LazyLock<std::sync::Mutex<Option<Py<PyModule>>>> =
    LazyLock::new(|| std::sync::Mutex::new(None));

/// Counter to make pinned memory buffer IDs unique across registrations.
static PINNED_COUNTER: LazyLock<std::sync::Mutex<u64>> = LazyLock::new(|| std::sync::Mutex::new(0));

/// Tracks freed pool buffer IDs so the DORADMA fast path can detect
/// read-after-free. Entries are inserted on free_memory_pool and never
/// pruned — bounded in practice by the total number of registrations
/// over the process lifetime.
static FREED_POOL_IDS: LazyLock<std::sync::Mutex<HashSet<String>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashSet::new()));

/// Per-pool persistent state.
/// Keeping Shmem alive prevents munmap, preserving stable mmap addresses
/// for pool-hit detection across `register_memory_pool` calls.
///
/// # Safety
/// `Shmem` is not `Send + Sync` due to raw pointer fields, but `PoolSlot`
/// is always stored behind a `Mutex` and `_shmem` is never accessed after
/// initialization — it is only kept alive for its destructor.
struct PoolSlot {
    _shmem: shared_memory_extended::Shmem,
    base: u64,
    size: usize,
    is_pinned: bool,
    /// CPU page-locked transit buffer for cross-device GPU transfers
    /// without P2P (e.g. RTX 5090).  0 means no transit path.
    transit_ptr: u64,
    /// The GPU device index where the pool buffer was allocated.
    pool_device: i32,
}

unsafe impl Send for PoolSlot {}
unsafe impl Sync for PoolSlot {}

/// Persistent pool storage — stable mmap addresses for zero-copy detection.
/// Keyed by counter (unique per registration), supports unlimited pools.
static PINNED_POOL: LazyLock<std::sync::Mutex<HashMap<u64, PoolSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// Receiver-side GPU cache per pool.
/// Keeps Shmem alive to prevent munmap, preserving stable mmap addresses
/// and valid GPU VAs for zero-copy reads across iterations.
struct RecvGpuSlot {
    _shmem: shared_memory_extended::Shmem,
    gpu_va: u64,       // device VA from cudaHostGetDevicePointer, 0 if IPC path
    gpu_buf: u64,      // IPC-opened GPU DRAM pointer, 0 if GPU VA path
    host_base: u64,    // original host ptr passed to cudaHostRegister
    gpu_buf_size: u64, // GPU buffer byte size from first import (baseline)
}

/// Daemon-trusted GPU buffer sizes, keyed by buffer_id.
/// Populated from daemon metadata when the fallback path successfully
/// re-imports a GPU IPC handle.  The fast path (`try_doradma_read`)
/// validates the (world-writable) shmem `size` against this cache —
/// if `size` exceeds the trusted capacity, the read is rejected and
/// the caller falls back to the daemon.
static GPU_BUF_SIZES: LazyLock<std::sync::Mutex<HashMap<String, u64>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));
unsafe impl Send for RecvGpuSlot {}
unsafe impl Sync for RecvGpuSlot {}

/// Receiver-side per-pool cache keeping Shmem alive + GPU VA for zero-copy reads.
/// Set up lazily in try_doradma_read: open shmem, cudaHostRegister,
/// cudaHostGetDevicePointer, then cache both Shmem and GPU VA.
static RECV_GPU_VA: LazyLock<std::sync::Mutex<HashMap<String, RecvGpuSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// Receiver-side per-pool Shmem cache for CPU receivers.
/// Keeps Shmem alive to prevent munmap of the CPU pointer returned
/// by the as_cuda=False path in try_doradma_read.
struct RecvCpuSlot {
    _shmem: shared_memory_extended::Shmem,
    base: u64,
}
unsafe impl Send for RecvCpuSlot {}
unsafe impl Sync for RecvCpuSlot {}

/// Receiver-side per-pool cache keeping Shmem alive for CPU zero-copy reads.
/// Without this cache, the Shmem handle drops at the end of try_doradma_read,
/// triggering munmap and making the returned CPU pointer a dangling pointer.
static RECV_CPU_SHMEM: LazyLock<std::sync::Mutex<HashMap<String, RecvCpuSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// DORADMA shared-memory header layout:
///
/// Offset  Size   Field
/// 0       8      magic      — b"DORADMA\x00"
/// 8       8      json_len   — u64 LE, metadata JSON byte length
/// 16      8      data_off   — u64 LE, byte offset of tensor data from shmem base
/// 24      8      ipc_flag   — u64 LE, 1 when ipc_handle is valid
/// 32      64     ipc_handle — CUDA IPC mem handle (only valid if ipc_flag == 1)
/// 96      8      write_gen  — u64 LE, seqlock: even = complete, odd = writing
/// 104     152    reserved
/// 256     N      json       — padded-to-256-byte-alignment metadata JSON
/// 256+N   M      data       — tensor payload
const DORADMA_HEADER_SIZE: usize = 256;
const DORADMA_MAGIC: &[u8; 8] = b"DORADMA\x00";
const DORADMA_METADATA_ALIGN: usize = 256;

/// Crossover where pinned-DMA bandwidth overtakes pageable copy +
/// cudaHostRegister/unregister fixed cost (~100 µs).  Determined by
/// ablation study (2026-06-27): pageable faster below, pinned faster
/// above.  Shared by `register_memory_pool` and `write_memory_pool`.
const DMA_PIN_THRESHOLD_BYTES: usize = 25 * 1024 * 1024;

/// Returns `true` when the source tensor should be pinned before DMA.
///
/// Pinning is a property of the *source* pointer: `cudaHostRegister` only
/// makes sense for host (CPU) memory, and the pin/unpin fixed cost
/// (~100 µs) is only worth paying when the tensor is large enough that
/// the DMA bandwidth gain outweighs it.
///
/// # Unit-testable
///
/// The decision is pure integer logic — no CUDA runtime calls — so the
/// boundary (25 MiB ± 1 byte) can be exercised in CI even without a GPU.
#[inline]
const fn should_pin(is_cuda: bool, size: usize) -> bool {
    !is_cuda && size > DMA_PIN_THRESHOLD_BYTES
}

#[cfg(test)]
mod pin_tests {
    use super::*;

    #[test]
    fn pin_cpu_source_above_threshold() {
        // CPU source, 25 MiB + 1 byte → should pin
        assert!(should_pin(false, 25 * 1024 * 1024 + 1));
        // CPU source, 100 MiB → should pin
        assert!(should_pin(false, 100 * 1024 * 1024));
    }

    #[test]
    fn pin_cpu_source_below_threshold() {
        // CPU source, exactly at threshold → should NOT pin (> not >=)
        assert!(!should_pin(false, 25 * 1024 * 1024));
        // CPU source, 1 byte below → should NOT pin
        assert!(!should_pin(false, 25 * 1024 * 1024 - 1));
        // CPU source, tiny → should NOT pin
        assert!(!should_pin(false, 1));
    }

    #[test]
    fn pin_cuda_source_never_pins() {
        // CUDA source regardless of size → never pin
        assert!(!should_pin(true, 0));
        assert!(!should_pin(true, 25 * 1024 * 1024));
        assert!(!should_pin(true, 100 * 1024 * 1024));
        assert!(!should_pin(true, 1024 * 1024 * 1024));
    }

    #[test]
    fn pin_zero_size_cpu() {
        // Zero-size CPU tensor → below threshold, don't pin
        assert!(!should_pin(false, 0));
    }
}

/// Get (or compile) the persistent CUDA DMA helper module.
///
/// Compiled once at first use and reused across all subsequent iterations.
/// The module maintains internal state for pinned host pointers and GPU buffers,
/// eliminating per-call cudaHostRegister/cudaMalloc/cudaFree/shm_open overhead.
fn get_cuda_helpers(py: Python<'_>) -> Result<Py<PyModule>, String> {
    let mut guard = CUDA_HELPERS.lock().unwrap_or_else(|e| e.into_inner());
    if let Some(ref module) = *guard {
        return Ok(module.clone_ref(py));
    }

    let code = r#"
import ctypes
_lib = ctypes.CDLL('libcudart.so')

_lib.cudaHostRegister.restype = ctypes.c_int
_lib.cudaHostRegister.argtypes = [ctypes.c_void_p, ctypes.c_size_t, ctypes.c_uint]

_lib.cudaHostUnregister.restype = ctypes.c_int
_lib.cudaHostUnregister.argtypes = [ctypes.c_void_p]

_lib.cudaMalloc.restype = ctypes.c_int
_lib.cudaMalloc.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_size_t]

_lib.cudaMemcpy.restype = ctypes.c_int
_lib.cudaMemcpy.argtypes = [ctypes.c_void_p, ctypes.c_void_p, ctypes.c_size_t, ctypes.c_int]

_lib.cudaFree.restype = ctypes.c_int
_lib.cudaFree.argtypes = [ctypes.c_void_p]

_lib.cudaDeviceSynchronize.restype = ctypes.c_int

_lib.cudaHostGetDevicePointer.restype = ctypes.c_int
_lib.cudaHostGetDevicePointer.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_void_p, ctypes.c_uint]

cudaMemcpyHostToDevice = 1

# IPC handle struct — must be a Structure subclass so ctypes passes it
# by value (64 bytes on the stack) to cudaIpcOpenMemHandle.
class _CudaIpcMemHandle(ctypes.Structure):
    _fields_ = [("reserved", ctypes.c_byte * 64)]

_lib.cudaIpcGetMemHandle.restype = ctypes.c_int
_lib.cudaIpcGetMemHandle.argtypes = [ctypes.POINTER(_CudaIpcMemHandle), ctypes.c_void_p]

_lib.cudaIpcOpenMemHandle.restype = ctypes.c_int
_lib.cudaIpcOpenMemHandle.argtypes = [ctypes.POINTER(ctypes.c_void_p), _CudaIpcMemHandle, ctypes.c_uint]

_lib.cudaIpcCloseMemHandle.restype = ctypes.c_int
_lib.cudaIpcCloseMemHandle.argtypes = [ctypes.c_void_p]

# Persistent state: per-slot GPU buffer cache
_gpu_bufs = {}    # slot -> (d_ptr, size)

def _register_host(ptr, size):
    """Pin host memory. Idempotent — error 712 (already registered) is ok."""
    err = _lib.cudaHostRegister(ctypes.c_void_p(ptr), size, 0)
    if err != 0 and err != 712:
        raise RuntimeError(f'cudaHostRegister(0x{ptr:x}, {size}) failed: {err}')

def _unregister_host(ptr):
    """Unpin host memory."""
    err = _lib.cudaHostUnregister(ctypes.c_void_p(ptr))
    if err != 0 and err != 713:
        raise RuntimeError(f'cudaHostUnregister(0x{ptr:x}) failed: {err}')

def _get_device_ptr(host_ptr):
    """Get a GPU VA for a pinned host memory region."""
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaHostGetDevicePointer(ctypes.byref(d_ptr), ctypes.c_void_p(host_ptr), 0)
    if err != 0:
        raise RuntimeError(f'cudaHostGetDevicePointer(0x{host_ptr:x}) failed: {err}')
    return d_ptr.value


# P2P and device query bindings (CUDA runtime).
_lib.cudaGetDevice.restype = ctypes.c_int
_lib.cudaGetDevice.argtypes = [ctypes.POINTER(ctypes.c_int)]
_lib.cudaDeviceCanAccessPeer.restype = ctypes.c_int
_lib.cudaDeviceCanAccessPeer.argtypes = [ctypes.POINTER(ctypes.c_int), ctypes.c_int, ctypes.c_int]
_lib.cudaDeviceEnablePeerAccess.restype = ctypes.c_int
_lib.cudaDeviceEnablePeerAccess.argtypes = [ctypes.c_int, ctypes.c_uint]
_lib.cudaSetDevice.restype = ctypes.c_int
_lib.cudaSetDevice.argtypes = [ctypes.c_int]

# Page-locked host allocation for cross-device staging buffers.
_lib.cudaHostAlloc.restype = ctypes.c_int
_lib.cudaHostAlloc.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_size_t, ctypes.c_uint]
_lib.cudaFreeHost.restype = ctypes.c_int
_lib.cudaFreeHost.argtypes = [ctypes.c_void_p]

_p2p_enabled_pairs = set()    # {(src, dst)} pairs already peer-enabled

def _alloc_transit(size):
    """Allocate a page-locked CPU buffer for cross-device staging.
    Returns the pointer (as int), or 0 on failure."""
    ptr = ctypes.c_void_p()
    if _lib.cudaHostAlloc(ctypes.byref(ptr), size, 0) == 0:
        return ptr.value
    return 0

def _free_transit(ptr):
    """Free a page-locked CPU transit buffer."""
    if ptr:
        _lib.cudaFreeHost(ctypes.c_void_p(ptr))

def _can_access_peer(src, dst):
    """Check if src GPU can P2P-access dst GPU. Returns bool."""
    can = ctypes.c_int(0)
    if _lib.cudaDeviceCanAccessPeer(ctypes.byref(can), src, dst) == 0:
        return can.value != 0
    return False

def _set_cuda_device(idx):
    """Set the current CUDA device.  No-op if *idx* < 0."""
    if idx >= 0:
        _lib.cudaSetDevice(idx)

def _get_cuda_device():
    """Return the current CUDA device index, or -1 on failure."""
    dev = ctypes.c_int()
    if _lib.cudaGetDevice(ctypes.byref(dev)) == 0:
        return dev.value
    return -1

def _transit_copy(src_ptr, src_dev, transit_ptr, dst_ptr, dst_dev, size):
    """Copy via CPU transit: src(GPU) → DtoH → transit → HtoD → dst(GPU).
    Returns True on success.  Restores the caller's current CUDA device on exit."""
    saved = ctypes.c_int()
    _lib.cudaGetDevice(ctypes.byref(saved))
    # GPU src → CPU transit
    _lib.cudaSetDevice(src_dev)
    err = _lib.cudaMemcpy(ctypes.c_void_p(transit_ptr), ctypes.c_void_p(src_ptr), size, 2)
    if err != 0:
        _lib.cudaSetDevice(saved.value)
        return False
    _lib.cudaDeviceSynchronize()
    # CPU transit → GPU dst
    _lib.cudaSetDevice(dst_dev)
    err = _lib.cudaMemcpy(ctypes.c_void_p(dst_ptr), ctypes.c_void_p(transit_ptr), size, 1)
    _lib.cudaDeviceSynchronize()
    _lib.cudaSetDevice(saved.value)
    return err == 0

def _transit_copy_gpu_buf(slot, src_ptr, src_dev, transit_ptr, dst_dev, size):
    """Same as _transit_copy but looks up the pool's GPU buffer by slot.
    Raises on a missing/undersized slot or a failed copy so the caller
    can surface the error instead of silently delivering stale data."""
    if slot not in _gpu_bufs:
        raise RuntimeError(f"GPU pool buffer for slot {slot} not initialised")
    dst, capacity = _gpu_bufs[slot]
    if size > capacity:
        raise RuntimeError(
            f"write size {size} exceeds GPU pool buffer capacity {capacity} (slot={slot})"
        )
    if not _transit_copy(src_ptr, src_dev, transit_ptr, dst, dst_dev, size):
        raise RuntimeError(f"transit copy into GPU pool buffer failed (slot={slot})")

def _ensure_p2p_pair(a, b):
    """Enable bidirectional P2P access for the (a, b) GPU pair only.

    Scoped to the sender/receiver devices actually used by a transfer —
    enabling P2P across *all* GPU pairs would lazily create a CUDA context
    (hundreds of MB) on every visible device, including ones not in this
    dataflow.  Idempotent per pair.
    """
    if a == b or a < 0 or b < 0:
        return
    if (a, b) in _p2p_enabled_pairs:
        return
    # Save the current device so we can restore it after enabling peer
    # access — otherwise later CUDA operations (cudaMalloc,
    # cudaIpcOpenMemHandle) would run on the last enabled src device.
    saved = ctypes.c_int()
    _lib.cudaGetDevice(ctypes.byref(saved))
    for src, dst in ((a, b), (b, a)):
        can = ctypes.c_int(0)
        if _lib.cudaDeviceCanAccessPeer(ctypes.byref(can), src, dst) == 0 and can.value:
            _lib.cudaSetDevice(src)
            _lib.cudaDeviceEnablePeerAccess(dst, 0)
        _p2p_enabled_pairs.add((src, dst))
    _lib.cudaSetDevice(saved.value)

def _cuda_memcpy(dst, src, size, kind):
    """cudaMemcpy wrapper. kind: 1=H2D, 2=D2H, 3=D2D."""
    err = _lib.cudaMemcpy(ctypes.c_void_p(dst), ctypes.c_void_p(src), size, kind)
    if err != 0:
        raise RuntimeError(f"cudaMemcpy(0x{dst:x}, 0x{src:x}, {size}, {kind}) failed: {err}")
    _lib.cudaDeviceSynchronize()

def _cuda_memcpy_gpu_buf(slot, src_ptr, size):
    """Copy *size* bytes from *src_ptr* (GPU) into the pool's pinned GPU buffer
    identified by *slot*.  Used by write_memory_pool when both source and pool
    buffer are GPU-resident (same-device DtoD copy)."""
    if slot not in _gpu_bufs:
        raise RuntimeError(f"GPU pool buffer for slot {slot} not initialised")
    dst, capacity = _gpu_bufs[slot]
    if size > capacity:
        # The GPU buffer was sized at registration and its IPC handle is
        # already exported; growing it would invalidate the receiver's
        # imported handle.  Reject rather than overflow the allocation.
        raise RuntimeError(
            f"write size {size} exceeds GPU pool buffer capacity {capacity} (slot={slot})"
        )
    err = _lib.cudaMemcpy(ctypes.c_void_p(dst), ctypes.c_void_p(src_ptr), size, 3)
    if err != 0:
        raise RuntimeError(f"cudaMemcpy GPU buf DtoD (slot={slot}, 0x{dst:x}←0x{src_ptr:x}, {size}B) failed: {err}")
    _lib.cudaDeviceSynchronize()

def _get_gpu_buf(slot, size):
    """Get or allocate a GPU buffer for the given slot. Reuses when size matches."""
    if slot in _gpu_bufs and _gpu_bufs[slot][1] >= size:
        return _gpu_bufs[slot][0]
    if slot in _gpu_bufs:
        _lib.cudaFree(ctypes.c_void_p(_gpu_bufs[slot][0]))
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaMalloc(ctypes.byref(d_ptr), size)
    if err != 0:
        raise RuntimeError(f'cudaMalloc({size}) failed: {err}')
    _gpu_bufs[slot] = (d_ptr.value, size)
    return d_ptr.value

def _free_gpu_buf(slot):
    """Free the pooled GPU buffer for the given slot."""
    if slot in _gpu_bufs:
        _lib.cudaFree(ctypes.c_void_p(_gpu_bufs[slot][0]))
        del _gpu_bufs[slot]

def _ipc_export(d_ptr):
    """Export GPU memory for cross-process sharing. Returns 64-byte handle."""
    handle = _CudaIpcMemHandle()
    err = _lib.cudaIpcGetMemHandle(ctypes.byref(handle), ctypes.c_void_p(d_ptr))
    if err != 0:
        raise RuntimeError(f'cudaIpcGetMemHandle(0x{d_ptr:x}) failed: {err}')
    return bytes(handle)

def _ipc_import(handle_bytes):
    """Import GPU memory from another process. Returns device pointer.

    cudaIpcOpenMemHandle takes the handle struct BY VALUE (64 bytes on
    the stack). _CudaIpcMemHandle.from_buffer_copy reconstructs the struct
    and ctypes copies it onto the stack for the call.
    """
    handle = _CudaIpcMemHandle.from_buffer_copy(handle_bytes)
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaIpcOpenMemHandle(ctypes.byref(d_ptr), handle, 1)
    if err != 0:
        raise RuntimeError(f'cudaIpcOpenMemHandle failed: {err}')
    _lib.cudaDeviceSynchronize()
    return d_ptr.value

def _ipc_close(d_ptr):
    """Close an IPC memory handle opened by _ipc_import.
    Frees the GPU-side mapping without freeing the underlying allocation."""
    err = _lib.cudaIpcCloseMemHandle(ctypes.c_void_p(d_ptr))
    if err != 0:
        raise RuntimeError(f'cudaIpcCloseMemHandle(0x{d_ptr:x}) failed: {err}')

def dma_copy(ptr, size, slot, no_dma):
    """DMA transfer from host to pre-allocated GPU buffer.

    Copies via cudaMemcpyHtoD (DMA engine).  When *no_dma* is false
    (the default), the source memory is pinned (cudaHostRegister)
    before the copy and unpinned after — this is the fast path for
    large tensors where pinned-DMA bandwidth outweighs the pin/unpin
    fixed cost.  When *no_dma* is true, pin/unpin is skipped, using
    pageable memory (faster for small tensors where pin overhead
    dominates).

    Returns the device pointer of the pooled GPU buffer.
    """
    if not no_dma:
        _register_host(ptr, size)
    try:
        d_ptr = _get_gpu_buf(slot, size)
        err = _lib.cudaMemcpy(
            ctypes.c_void_p(d_ptr),
            ctypes.c_void_p(ptr),
            size,
            cudaMemcpyHostToDevice,
        )
        if err != 0:
            raise RuntimeError(f'cudaMemcpy failed: {err}')
        _lib.cudaDeviceSynchronize()
    finally:
        if not no_dma:
            _unregister_host(ptr)
    return d_ptr

"#;

    let code_cstr = std::ffi::CString::new(code).map_err(|e| format!("CString: {}", e))?;
    let bound_module = PyModule::from_code(
        py,
        code_cstr.as_c_str(),
        c"_cuda_helpers.py",
        c"_cuda_helpers",
    )
    .map_err(|e| format!("CUDA helper compile failed: {}", e))?;
    let module_ref: Py<PyModule> = bound_module.unbind();
    *guard = Some(module_ref.clone_ref(py));
    Ok(module_ref)
}

/// Read 8 consecutive bytes from `p` as a little-endian u64,
/// without an `.unwrap()` call (avoids the CI unwrap budget).
fn read_header_u64(p: *const u8) -> u64 {
    const { assert!(std::mem::size_of::<u64>() == 8) };
    let mut buf = [0u8; 8];
    unsafe { std::ptr::copy_nonoverlapping(p, buf.as_mut_ptr(), 8) };
    u64::from_le_bytes(buf)
}

fn parse_memory_pool_id(memory_pool_id: Py<PyAny>, py: Python<'_>) -> eyre::Result<String> {
    let array_data = arrow::array::ArrayData::from_pyarrow_bound(memory_pool_id.bind(py))?;
    let array = arrow::array::make_array(array_data);

    if let Some(string_array) = array.as_any().downcast_ref::<StringArray>() {
        if string_array.len() != 1 {
            eyre::bail!(
                "expected string array with exactly one element, got {}",
                string_array.len()
            );
        }
        Ok(string_array.value(0).to_string())
    } else if let Some(binary_array) = array.as_any().downcast_ref::<BinaryArray>() {
        if binary_array.len() != 1 {
            eyre::bail!(
                "expected binary array with exactly one element, got {}",
                binary_array.len()
            );
        }
        Ok(String::from_utf8(binary_array.value(0).to_vec())?)
    } else {
        eyre::bail!(
            "memory_pool_id must be a string or binary array, got {:?}",
            array.data_type()
        )
    }
}

fn warn_missing_memory_pool(node_id: &NodeId, action: &str, buffer_id: &str) {
    tracing::warn!(
        "[{}] Attempt to {} memory pool [{}] failed - reason: pool does not exist. Operation aborted.",
        node_id,
        action,
        buffer_id
    );
}

/// The custom node API lets you integrate `dora` into your application.
/// It allows you to retrieve input and send output in any fashion you want.
///
/// Use with:
///
/// ```python
/// from dora import Node
///
/// node = Node()
/// ```
///
/// :type node_id: str, optional
#[pyclass]
pub struct Node {
    events: Events,
    node: DelayedCleanup<DoraNode>,

    dataflow_id: DataflowId,
    node_id: NodeId,
}

#[pymethods]
impl Node {
    #[new]
    #[pyo3(signature = (node_id=None, daemon_port=None))]
    pub fn new(node_id: Option<String>, daemon_port: Option<u16>) -> eyre::Result<Self> {
        let (node, events) = if let Some(node_id) = node_id {
            let node_id = node_id.parse::<NodeId>().map_err(|e| eyre::eyre!("{e}"))?;
            if let Some(port) = daemon_port {
                DoraNode::builder()
                    .node_id(node_id)
                    .daemon_port(port)
                    .build()
                    .map_err(|e| eyre::eyre!("{e}"))
                    .context("Could not setup node from node id with custom daemon port")?
            } else {
                // No explicit port: keep the flexible DORA_NODE_CONFIG-first behavior.
                DoraNode::init_flexible(node_id)
                    .context("Could not setup node from node id. Make sure to have a running dataflow with this dynamic node")?
            }
        } else {
            DoraNode::init_from_env().context("Could not initiate node from environment variable. For dynamic node, please add a node id in the initialization function.")?
        };
        let id = node.id().clone();
        let dataflow_id = *node.dataflow_id();
        runtime()?.spawn(async move {
            let _guard = init_tracing(&id, &dataflow_id).unwrap();
            loop {
                tokio::time::sleep(std::time::Duration::from_secs(1)).await;
            }
        });

        let dataflow_id = *node.dataflow_id();
        let node_id = node.id().clone();
        let node = DelayedCleanup::new(node);
        let events = events;
        let cleanup_handle = NodeCleanupHandle {
            _handles: Arc::new(node.handle()),
        };

        Python::attach(|py| {
            // Extend the `logging` module to interact with tracing
            setup_logging(py)
        })?;

        Ok(Node {
            events: Events {
                inner: Arc::new(Mutex::new(EventsInner::Dora(events))),
                _cleanup_handle: cleanup_handle,
            },
            dataflow_id,
            node_id,
            node,
        })
    }

    /// `.next()` gives you the next input that the node has received.
    /// It blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return `None` when all senders has been dropped.
    ///
    /// ```python
    /// event = node.next()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub fn next(&self, py: Python, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = py.detach(|| self.events.recv(timeout.map(Duration::from_secs_f32)));
        if let Some(event) = event {
            let dict = event
                .to_py_dict(py)
                .context("Could not convert event into a dict")?;
            Ok(Some(dict))
        } else {
            Ok(None)
        }
    }

    /// `.drain()` gives you all available inputs that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// events = node.drain()
    /// for event in events:
    ///     print(event)
    /// ```
    ///
    /// :rtype: list[dict]
    #[allow(clippy::should_implement_trait)]
    pub fn drain(&self, py: Python) -> PyResult<Vec<Py<PyDict>>> {
        let events = self
            .events
            .drain()
            .context("Could not drain events. Channel is closed")?
            .into_iter()
            .map(|event| {
                event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")
                    .unwrap_or_else(|err| {
                        tracing::warn!("failed to convert event to dict: {err:?}");
                        PyDict::new(py).into()
                    })
            })
            .collect();
        Ok(events)
    }

    /// `.try_recv()` gives you the next input in the queue that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// event = events.try_recv()
    ///     print(event)
    /// ```
    ///
    /// :rtype: dict
    #[allow(clippy::should_implement_trait)]
    pub fn try_recv(&mut self, py: Python) -> Option<Py<PyDict>> {
        match self.events.try_recv() {
            Ok(event) => event.to_py_dict(py).ok(),
            Err(_) => None,
        }
    }

    /// Check if there are any buffered events in the event stream.
    ///
    /// :rtype: bool
    #[allow(clippy::should_implement_trait)]
    pub fn is_empty(&self) -> bool {
        self.events.is_empty()
    }

    /// `.recv_async()` gives you the next input that the node has received asynchronously.
    /// It does not blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return an Error if the timeout is reached.
    /// It will return `None` when all senders has been dropped.
    ///
    /// warning::
    ///     This feature is experimental as pyo3 async (rust-python FFI) is still in development.
    ///
    /// ```python
    /// event = await node.recv_async()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub async fn recv_async(&self, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = self
            .events
            .recv_async_timeout(timeout.map(Duration::from_secs_f32))
            .await;
        if let Some(event) = event {
            // Get python
            Python::attach(|py| {
                let dict = event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")?;

                Ok(Some(dict))
            })
        } else {
            Ok(None)
        }
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// Default behaviour is to timeout after 2 seconds.
    ///
    /// :rtype: dict
    pub fn __next__(&self, py: Python) -> PyResult<Option<Py<PyDict>>> {
        self.next(py, None)
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :rtype: dict
    fn __iter__(slf: PyRef<'_, Self>) -> PyRef<'_, Self> {
        slf
    }

    /// `send_output` send data from the node.
    ///
    /// ```python
    /// Args:
    ///    output_id: str,
    ///    data: pyarrow.Array,
    ///    metadata: Option[Dict],
    /// ```
    ///
    /// ex:
    ///
    /// ```python
    /// node.send_output("string", b"string", {"open_telemetry_context": "7632e76"})
    /// ```
    ///
    /// :type output_id: str
    /// :type data: pyarrow.Array
    /// :type metadata: dict, optional
    /// :rtype: None
    #[pyo3(signature = (output_id, data, metadata=None))]
    pub fn send_output(
        &self,
        output_id: String,
        data: Py<PyAny>,
        metadata: Option<Bound<'_, PyDict>>,
        py: Python,
    ) -> eyre::Result<()> {
        let parameters = pydict_to_metadata(metadata)?;

        if let Ok(py_bytes) = data.cast_bound::<PyBytes>(py) {
            let data = py_bytes.as_bytes();
            self.node
                .get_mut()
                .send_output_bytes(output_id.into(), parameters, data.len(), data)
                .wrap_err("failed to send output")?;
        } else if let Ok(arrow_array) = arrow::array::ArrayData::from_pyarrow_bound(data.bind(py)) {
            self.node.get_mut().send_output(
                output_id.into(),
                parameters,
                arrow::array::make_array(arrow_array),
            )?;
        } else {
            eyre::bail!("invalid `data` type, must by `PyBytes` or arrow array")
        }

        Ok(())
    }

    /// `send_output_raw` send data from the node via a writable buffer (zero-copy).
    ///
    /// Returns a :class:`SampleHandler` that pre-allocates `data_length` bytes
    /// of shared-memory- or aligned-heap-backed storage. Fill the buffer via
    /// Python's buffer protocol (`memoryview`, `numpy.frombuffer`, `struct`, ...)
    /// and then call ``.send()`` — or use the context-manager form which sends
    /// on ``__exit__``.
    ///
    /// Requires Python >= 3.11 (uses the stable buffer-protocol slots).
    ///
    /// ## Wire format
    ///
    /// The buffer is sent as a 1-D Arrow ``UInt8`` array inside an Arrow IPC stream.
    /// On the receive side, ``event["value"]`` is a ``pyarrow.UInt8Array`` /
    /// ``LargeBinary`` shape — call ``.to_numpy()`` for a numpy view, then
    /// ``.reshape(...)`` or ``.view(dtype=...)`` to interpret it as a typed
    /// payload. Genuine typed zero-copy (sending an ``Int32Array``,
    /// ``Float32Array``, etc. directly via this path) is a follow-up — the
    /// current buffer-protocol shape is bytes-only because the buffer protocol
    /// itself works in bytes and Arrow's typed metadata would need a separate
    /// channel. Use the existing :meth:`send_output` (with one copy) when you
    /// need a typed Arrow payload today.
    ///
    /// Example (recommended, context manager):
    ///
    /// ```python
    /// with node.send_output_raw("rgb_image", 1920 * 1080 * 3, {"width": 1920}) as buf:
    ///     numpy.frombuffer(buf, numpy.uint8).reshape(1080, 1920, 3)[:] = frame
    /// # data is sent automatically on __exit__. The yielded `buf` is a
    /// # SampleBuffer; any derived consumer (numpy, memoryview, struct)
    /// # must be released before `with` exits or send() refuses.
    /// ```
    ///
    /// Manual send:
    ///
    /// ```python
    /// sample = node.send_output_raw("rgb_image", data_length)
    /// mv = sample.as_memoryview()
    /// mv[:] = your_data
    /// mv.release()
    /// sample.send()
    /// ```
    ///
    /// :type output_id: str
    /// :type data_length: int
    /// :type metadata: dict, optional
    /// :rtype: SampleHandler
    #[cfg(Py_3_11)]
    #[pyo3(signature = (output_id, data_length, metadata=None))]
    pub fn send_output_raw(
        &self,
        output_id: String,
        data_length: usize,
        metadata: Option<Bound<'_, PyDict>>,
        _py: Python,
    ) -> eyre::Result<SampleHandler> {
        let parameters = pydict_to_metadata(metadata)?;
        let data_id: DataId = output_id
            .parse()
            .map_err(|e| eyre::eyre!("invalid output_id: {e}"))?;
        if !self.node.get_mut().validate_output(&data_id) {
            eyre::bail!("Output `{data_id}` not in node's output list.")
        }
        SampleHandler::new(data_length, data_id, parameters, self.node.clone())
    }

    /// Send a service request, automatically injecting a ``request_id`` into
    /// the metadata. Returns the generated request ID (UUID v7).
    ///
    /// This is a convenience wrapper around :meth:`send_output` for the
    /// request/reply pattern.
    ///
    /// :param output_id: The output port to send on
    /// :type output_id: str
    /// :param data: Arrow array or bytes payload
    /// :type data: pyarrow.Array or bytes
    /// :param metadata: Additional metadata parameters (optional)
    /// :type metadata: dict, optional
    /// :rtype: str
    #[pyo3(signature = (output_id, data, metadata=None))]
    pub fn send_service_request(
        &self,
        output_id: String,
        data: Py<PyAny>,
        metadata: Option<Bound<'_, PyDict>>,
        py: Python,
    ) -> eyre::Result<String> {
        let mut parameters = pydict_to_metadata(metadata)?;
        if parameters.contains_key(dora_message::metadata::REQUEST_ID) {
            tracing::warn!(
                "send_service_request: overwriting caller-provided 'request_id' \
                 with auto-generated value"
            );
        }
        let request_id = dora_node_api::DoraNode::new_request_id();
        parameters.insert(
            dora_message::metadata::REQUEST_ID.to_string(),
            dora_message::metadata::Parameter::String(request_id.clone()),
        );

        if let Ok(py_bytes) = data.cast_bound::<PyBytes>(py) {
            let data = py_bytes.as_bytes();
            self.node
                .get_mut()
                .send_output_bytes(output_id.into(), parameters, data.len(), data)
                .wrap_err("failed to send service request")?;
        } else if let Ok(arrow_array) = arrow::array::ArrayData::from_pyarrow_bound(data.bind(py)) {
            self.node.get_mut().send_output(
                output_id.into(),
                parameters,
                arrow::array::make_array(arrow_array),
            )?;
        } else {
            eyre::bail!("invalid `data` type, must be `PyBytes` or arrow array")
        }

        Ok(request_id)
    }

    /// Send a service response. Convenience wrapper around :meth:`send_output`
    /// that passes through the ``request_id`` from the incoming request metadata.
    ///
    /// :param output_id: The output port to send on
    /// :type output_id: str
    /// :param data: Arrow array or bytes payload
    /// :type data: pyarrow.Array or bytes
    /// :param metadata: Metadata dict (required) — must include ``request_id`` from the request
    /// :type metadata: dict (required)
    /// :rtype: None
    #[pyo3(signature = (output_id, data, metadata))]
    pub fn send_service_response(
        &self,
        output_id: String,
        data: Py<PyAny>,
        metadata: Bound<'_, PyDict>,
        py: Python,
    ) -> eyre::Result<()> {
        let parameters = pydict_to_metadata(Some(metadata))?;

        if !parameters.contains_key(dora_message::metadata::REQUEST_ID) {
            tracing::warn!(
                "send_service_response: metadata is missing 'request_id' \
                 — response will not be matched to a request"
            );
        }

        if let Ok(py_bytes) = data.cast_bound::<PyBytes>(py) {
            let data = py_bytes.as_bytes();
            self.node
                .get_mut()
                .send_output_bytes(output_id.into(), parameters, data.len(), data)
                .wrap_err("failed to send service response")?;
        } else if let Ok(arrow_array) = arrow::array::ArrayData::from_pyarrow_bound(data.bind(py)) {
            self.node.get_mut().send_output(
                output_id.into(),
                parameters,
                arrow::array::make_array(arrow_array),
            )?;
        } else {
            eyre::bail!("invalid `data` type, must be `PyBytes` or arrow array")
        }

        Ok(())
    }

    /// Send a structured log message.
    ///
    /// Outputs a JSONL line to stdout that the daemon parses automatically.
    /// Works with ``min_log_level`` filtering and ``send_logs_as`` routing.
    ///
    /// :param level: Log level string (error, warn, info, debug, trace)
    /// :type level: str
    /// :param message: The log message
    /// :type message: str
    /// :param target: Optional target/module path
    /// :type target: str, optional
    /// :param fields: Optional key-value pairs for structured context
    /// :type fields: dict[str, str], optional
    /// :rtype: None
    #[pyo3(signature = (level, message, target=None, fields=None))]
    pub fn log(
        &self,
        level: &str,
        message: &str,
        target: Option<&str>,
        fields: Option<std::collections::HashMap<String, String>>,
    ) {
        let ordered = fields.map(|f| f.into_iter().collect::<std::collections::BTreeMap<_, _>>());
        self.node
            .get_mut()
            .log_with_fields(level, message, target, ordered.as_ref());
    }

    /// Log an error message.
    ///
    /// Shorthand for ``node.log("error", message)``.
    ///
    /// :param message: The log message
    /// :type message: str
    /// :rtype: None
    pub fn log_error(&self, message: &str) {
        self.node.get_mut().log_error(message);
    }

    /// Log a warning message.
    ///
    /// Shorthand for ``node.log("warn", message)``.
    ///
    /// :param message: The log message
    /// :type message: str
    /// :rtype: None
    pub fn log_warn(&self, message: &str) {
        self.node.get_mut().log_warn(message);
    }

    /// Log an info message.
    ///
    /// Shorthand for ``node.log("info", message)``.
    ///
    /// :param message: The log message
    /// :type message: str
    /// :rtype: None
    pub fn log_info(&self, message: &str) {
        self.node.get_mut().log_info(message);
    }

    /// Log a debug message.
    ///
    /// Shorthand for ``node.log("debug", message)``.
    ///
    /// :param message: The log message
    /// :type message: str
    /// :rtype: None
    pub fn log_debug(&self, message: &str) {
        self.node.get_mut().log_debug(message);
    }

    /// Log a trace message.
    ///
    /// Shorthand for ``node.log("trace", message)``.
    ///
    /// :param message: The log message
    /// :type message: str
    /// :rtype: None
    pub fn log_trace(&self, message: &str) {
        self.node.get_mut().log_trace(message);
    }

    /// Returns the full dataflow descriptor that this node is part of.
    ///
    /// This method returns the parsed dataflow YAML file.
    ///
    /// :rtype: dict
    pub fn dataflow_descriptor(&self, py: Python) -> eyre::Result<Py<PyAny>> {
        Ok(
            pythonize::pythonize(py, &self.node.get_mut().dataflow_descriptor()?)
                .map(|x| x.unbind())?,
        )
    }

    /// Returns the node configuration.
    ///
    /// :rtype: dict
    pub fn node_config(&self, py: Python) -> eyre::Result<Py<PyAny>> {
        Ok(pythonize::pythonize(py, &self.node.get_mut().node_config()).map(|x| x.unbind())?)
    }

    /// Returns the dataflow id.
    ///
    /// :rtype: str
    pub fn dataflow_id(&self) -> String {
        self.dataflow_id.to_string()
    }

    /// Returns True if this node was restarted after a previous exit or failure.
    ///
    /// Nodes can use this to decide whether to restore saved state or start fresh.
    ///
    /// :rtype: bool
    pub fn is_restart(&self) -> bool {
        self.node.get_mut().is_restart()
    }

    /// Returns how many times this node has been restarted.
    ///
    /// Returns 0 on the first run, 1 after the first restart, etc.
    ///
    /// :rtype: int
    pub fn restart_count(&self) -> u32 {
        self.node.get_mut().restart_count()
    }

    /// Returns the current timestamp from the node's Hybrid Logical Clock
    /// as a UTC datetime object.
    ///
    /// Use this against ``event["metadata"]["timestamp"]`` from an INPUT
    /// event to compute per-event processing latency against the same
    /// clock dora uses on its data plane.
    ///
    /// **Resolution & ordering caveats** — Python ``datetime`` is
    /// microsecond-resolution and only carries the HLC's physical
    /// component; its logical counter is dropped. Two messages produced
    /// in the same HLC microsecond will compare equal here even though
    /// the underlying HLC distinguishes them. For strict ordering use
    /// the Rust API (``DoraNode::timestamp() -> uhlc::Timestamp``).
    ///
    /// **Threading** — like every other ``Node`` method, this acquires
    /// the node's internal mutex via ``try_lock`` and will panic if
    /// another thread is mid-call into the same ``Node`` instance. The
    /// Python GIL serialises in-process calls, so this is only
    /// reachable if a caller releases the GIL (e.g. via
    /// ``allow_threads``) and another thread re-enters the same Node.
    /// Don't do that.
    ///
    /// :rtype: datetime.datetime
    pub fn timestamp(&self, py: Python) -> eyre::Result<Py<PyAny>> {
        let ts = self.node.get_mut().timestamp();
        let system_time = ts.get_time().to_system_time();
        let duration_since_epoch = system_time
            .duration_since(std::time::UNIX_EPOCH)
            .context("Failed to calculate duration since epoch")?;
        let total_seconds = duration_since_epoch.as_secs() as f64
            + duration_since_epoch.subsec_micros() as f64 / 1_000_000.0;
        let dt_module = datetime_module(py).context("Failed to import datetime module")?;
        let datetime_class = dt_module.getattr("datetime")?;
        let utc_timezone = dt_module.getattr("timezone")?.getattr("utc")?;
        let py_datetime =
            datetime_class.call_method1("fromtimestamp", (total_seconds, utc_timezone))?;
        Ok(py_datetime.unbind())
    }

    /// Merge an external event stream with dora main loop.
    /// This currently only work with ROS2.
    ///
    /// :type subscription: dora.Ros2Subscription
    /// :rtype: None
    pub fn merge_external_events(
        &self,
        py: Python,
        subscription: &mut Ros2Subscription,
    ) -> eyre::Result<()> {
        let subscription = subscription.into_stream()?;
        let stream = futures::stream::poll_fn(move |cx| {
            let s = subscription.as_stream().map(|item| {
                match item.context("failed to read ROS2 message") {
                    Ok((value, _info)) => Python::attach(|py| {
                        value
                            .to_pyarrow(py)
                            .map(|b| b.unbind())
                            .context("failed to convert value to pyarrow")
                            .unwrap_or_else(|err| err_to_pyany(err, py))
                    }),
                    Err(err) => Python::attach(|py| err_to_pyany(err, py)),
                }
            });
            futures::pin_mut!(s);
            s.poll_next_unpin(cx)
        });

        // Release the GIL while blocking on the node's event mutex. Holding the
        // GIL across `blocking_lock()` can deadlock against a suspended
        // `recv_async` task that holds the same lock (`inner.lock().await`) and
        // needs the GIL to make progress (dora-rs/dora#2027). Clone the `Arc` so
        // the closure doesn't capture `&self` (keeping the `Ungil` bound clean).
        let inner = self.events.inner.clone();
        py.detach(move || {
            // take out the event stream and temporarily replace it with a dummy
            let mut guard = inner.blocking_lock();
            let events = std::mem::replace(
                &mut *guard,
                EventsInner::Merged(Box::new(futures::stream::empty())),
            );
            // update the stream with the merged one
            *guard = EventsInner::Merged(events.merge_external_send(Box::pin(stream)));
        });

        Ok(())
    }

    // === Memory Pool API ===

    /// Register a shared memory pool for zero-copy tensor transfer.
    ///
    /// The returned pool ID can be shared across nodes (e.g. via a Dora output)
    /// so that a receiver can call [`read_memory_pool`] and [`free_memory_pool`]
    /// on it.
    ///
    /// # Concurrency / safety
    ///
    /// **This pool provides no internal mutual exclusion for data bytes.**
    /// The writer must not begin a new [`write_memory_pool`] while a receiver is
    /// still consuming the previous tensor. Callers that share a pool across
    /// nodes MUST enforce a **turn-based discipline** — for example, by waiting
    /// for a `next_require` round-trip from the receiver before writing again.
    /// The bundled `examples/memory-pool/` dataflows demonstrate this pattern.
    ///
    /// The on-segment seqlock guards metadata integrity (header fields written
    /// once at registration) and detects in-flight overwrites, but it does
    /// **not** block the writer from starting a new write while a consumer
    /// holds a zero-copy tensor. Skipping the turn-based discipline risks
    /// torn data at the consumer.
    #[pyo3(signature = (tensor_info, device))]
    pub fn register_memory_pool(
        &self,
        tensor_info: &Bound<'_, PyDict>,
        device: String,
        py: Python,
    ) -> eyre::Result<Py<PyAny>> {
        let ptr_val: u64 = tensor_info
            .get_item("ptr")?
            .ok_or_else(|| eyre::eyre!("missing ptr"))?
            .extract()?;
        let size: usize = tensor_info
            .get_item("size")?
            .ok_or_else(|| eyre::eyre!("missing size"))?
            .extract()?;
        let dtype: String = tensor_info
            .get_item("dtype")?
            .ok_or_else(|| eyre::eyre!("missing dtype"))?
            .extract()?;
        let shape_list: Vec<i64> = tensor_info
            .get_item("shape")?
            .ok_or_else(|| eyre::eyre!("missing shape"))?
            .extract()?;
        let tensor_device: String = tensor_info
            .get_item("device")?
            .ok_or_else(|| eyre::eyre!("missing device"))?
            .extract()?;

        let is_cuda = tensor_device.starts_with("cuda");
        let receiver_is_cuda = device.starts_with("cuda");
        let cpu_mode = !receiver_is_cuda;
        // Auto-select pinning: key off the source device — pinning only
        // matters when the source is CPU (cudaHostRegister would raise on a
        // device pointer; prevented by the !is_cuda guard above).
        let is_pinned = should_pin(is_cuda, size);
        let pinned_type = if cpu_mode { "cpu" } else { "cuda" };

        if ptr_val == 0 {
            eyre::bail!("Invalid source pointer (NULL)");
        }
        if size == 0 || size > 1024 * 1024 * 1024 {
            eyre::bail!("Invalid size: {} bytes", size);
        }
        if cfg!(not(target_os = "linux")) {
            eyre::bail!(
                "memory-pool transport requires Linux (uses /dev/shm). \
                 This platform is not supported."
            );
        }

        // Generate unique pool counter for this registration
        let pool_counter = {
            let mut c = PINNED_COUNTER.lock().unwrap_or_else(|e| e.into_inner());
            *c += 1;
            *c
        };
        let shmem_name = format!(
            "dora_pool_{}_{}_{}",
            self.dataflow_id, self.node_id, pool_counter
        );

        let header_meta = PyDict::new(py);
        header_meta.set_item("size", size)?;
        header_meta.set_item("dtype", &dtype)?;
        header_meta.set_item("shape", shape_list.clone())?;
        header_meta.set_item("pinned_type", pinned_type)?;

        let json_bytes = py
            .import("json")
            .wrap_err("failed to import json")?
            .call_method1("dumps", (header_meta,))
            .wrap_err("failed to serialize metadata to JSON")?
            .extract::<String>()
            .wrap_err("failed to extract JSON string")?
            .into_bytes();
        let json_len = json_bytes.len();
        let padded_json_len = json_len.div_ceil(DORADMA_METADATA_ALIGN) * DORADMA_METADATA_ALIGN;
        let data_offset = DORADMA_HEADER_SIZE + padded_json_len;
        // GPU receivers read tensor data from the IPC-exported GPU buffer,
        // not from the shmem data region.  Allocate only the header portion
        // (metadata + IPC handle + seqlock) — a few hundred bytes instead of
        // 80 MB.  This also lets us skip cudaHostRegister on a useless data
        // region.
        let total_size = if receiver_is_cuda {
            data_offset
        } else {
            data_offset + size
        };

        // Create shared memory
        let mut shmem = ShmemConf::new()
            .os_id(&shmem_name)
            .size(total_size)
            .writable(true)
            .create()
            .wrap_err_with(|| {
                format!(
                    "failed to create pool shared memory `{}` (name collision with another node or leftover segment)",
                    shmem_name
                )
            })?;
        let shmem_ptr = unsafe { shmem.as_slice_mut().as_mut_ptr() };

        // Pin the shmem for DMA only when the receiver reads from it
        // (CPU receivers).  GPU receivers never touch the shmem data
        // region, and the header-only shmem is too small (< 1 page) to
        // benefit from pinning.
        if !receiver_is_cuda {
            if let Ok(helpers) = get_cuda_helpers(py) {
                let bound = helpers.bind(py);
                let _ = bound.call_method1("_register_host", (shmem_ptr as u64, total_size));
            }
        }

        shmem.set_owner(false);

        // Write DORADMA header
        unsafe {
            std::ptr::copy_nonoverlapping(DORADMA_MAGIC.as_ptr(), shmem_ptr, 8);
            let json_len_le = (json_len as u64).to_le_bytes();
            std::ptr::copy_nonoverlapping(json_len_le.as_ptr(), shmem_ptr.add(8), 8);
            let data_off_le = (data_offset as u64).to_le_bytes();
            std::ptr::copy_nonoverlapping(data_off_le.as_ptr(), shmem_ptr.add(16), 8);
            std::ptr::copy_nonoverlapping(
                json_bytes.as_ptr(),
                shmem_ptr.add(DORADMA_HEADER_SIZE),
                json_len,
            );
        }

        // Initialize seqlock write_gen at header[96] to 0 (even = complete)
        unsafe {
            std::ptr::write(shmem_ptr.add(96) as *mut u64, 0u64);
        }

        // Seqlock: increment gen to odd (write-in-progress)
        unsafe {
            let gen_ptr = shmem_ptr.add(96) as *mut u64;
            let old_gen = std::ptr::read_volatile(gen_ptr);
            std::ptr::write_volatile(gen_ptr, old_gen + 1);
            std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
        }

        // Copy tensor data to shmem — only when the receiver will
        // actually read it.  GPU receivers import the pool GPU buffer
        // via the IPC handle in the DORADMA header and never touch the
        // shmem data region; skipping this copy for them eliminates
        // a redundant CPU-memcpy or GPU-DtoH transfer on every
        // registration (cpu2cuda and cuda2cuda respectively).
        if !receiver_is_cuda {
            if is_cuda {
                if let Ok(helpers) = get_cuda_helpers(py) {
                    let bound = helpers.bind(py);
                    let _ = bound.call_method1(
                        "_cuda_memcpy",
                        (shmem_ptr as u64 + data_offset as u64, ptr_val, size, 2u32),
                    );
                }
            } else {
                unsafe {
                    std::ptr::copy_nonoverlapping(
                        ptr_val as *const u8,
                        shmem_ptr.add(data_offset),
                        size,
                    );
                }
            }
        }

        // GPU pool: allocate GPU buffer on current device, copy data, export
        // IPC handle for cross-process zero-copy access.  When the source
        // tensor is also on CUDA (GPU→GPU), the source and pool buffer are on
        // the same device (sender's current CUDA device), so a plain DtoD
        // memcpy suffices.  When the source is CPU, `dma_copy` does a pinned
        // host→device DMA copy (existing path).
        // Resolve sender and receiver device indices for cross-device detection.
        let sender_device_idx = tensor_device
            .strip_prefix("cuda")
            .and_then(|s| s.strip_prefix(':'))
            .and_then(|s| s.parse::<i32>().ok())
            .unwrap_or(0);
        let receiver_device_idx = device
            .strip_prefix("cuda")
            .and_then(|s| s.strip_prefix(':'))
            .and_then(|s| s.parse::<i32>().ok())
            .unwrap_or(0);
        let cross_device = sender_device_idx != receiver_device_idx;
        let mut transit_ptr: u64 = 0;
        let mut pool_device = sender_device_idx;

        // Tracks whether the GPU pool buffer + IPC handle were successfully set
        // up.  A CUDA receiver's shmem is header-only, so without the handle the
        // pool is unusable — we fail registration rather than hand back a
        // permanently-broken pool.
        let mut ipc_written = false;

        if receiver_is_cuda && let Ok(helpers) = get_cuda_helpers(py) {
            let bound = helpers.bind(py);

            // Enable P2P for the sender/receiver pair before any IPC operations.
            let _ =
                bound.call_method1("_ensure_p2p_pair", (sender_device_idx, receiver_device_idx));

            // Cross-device without P2P needs CPU transit (e.g. RTX 5090).
            // Check P2P availability via the Python helper.
            let p2p_available: bool = cross_device
                && bound
                    .call_method1("_can_access_peer", (sender_device_idx, receiver_device_idx))
                    .and_then(|r| r.extract::<bool>())
                    .unwrap_or(false);
            let use_transit = cross_device && !p2p_available;

            let gpu_ptr: Option<u64> = if is_cuda {
                if use_transit {
                    // Allocate pool buffer on receiver's GPU so the
                    // receiver can import the IPC handle on its own device.
                    let _ = bound.call_method1("_set_cuda_device", (receiver_device_idx,));
                    let dst: u64 = bound
                        .call_method1("_get_gpu_buf", (pool_counter, size))
                        .and_then(|r| r.extract::<u64>())
                        .unwrap_or(0);
                    // Switch back to sender device.
                    let _ = bound.call_method1("_set_cuda_device", (sender_device_idx,));
                    if dst != 0 {
                        // Allocate CPU page-locked transit buffer.
                        let tp: u64 = bound
                            .call_method1("_alloc_transit", (size,))
                            .and_then(|r| r.extract::<u64>())
                            .unwrap_or(0);
                        if tp != 0 {
                            // Copy via transit: sender GPU → CPU → receiver GPU.
                            let ok: bool = bound
                                .call_method1(
                                    "_transit_copy",
                                    (
                                        ptr_val,
                                        sender_device_idx,
                                        tp,
                                        dst,
                                        receiver_device_idx,
                                        size,
                                    ),
                                )
                                .and_then(|r| r.extract::<bool>())
                                .unwrap_or(false);
                            if ok {
                                transit_ptr = tp;
                                pool_device = receiver_device_idx;
                                Some(dst)
                            } else {
                                // _transit_copy failed: free both buffers
                                let _ = bound.call_method1("_free_transit", (tp,));
                                let _ = bound.call_method1("_free_gpu_buf", (pool_counter,));
                                None
                            }
                        } else {
                            // transit alloc failed: free GPU buffer
                            let _ = bound.call_method1("_free_gpu_buf", (pool_counter,));
                            None
                        }
                    } else {
                        None
                    }
                } else {
                    // Same-device or P2P available: allocate on sender device.
                    // Save the current device — the ambient CUDA device may
                    // differ from the tensor device — and restore before
                    // returning so later cudaMalloc calls land on the right GPU.
                    let saved_dev: i32 = bound
                        .call_method0("_get_cuda_device")
                        .and_then(|r| r.extract::<i32>())
                        .unwrap_or(0);
                    let _ = bound.call_method1("_set_cuda_device", (sender_device_idx,));
                    let result = {
                        let dst: u64 = bound
                            .call_method1("_get_gpu_buf", (pool_counter, size))
                            .and_then(|r| r.extract::<u64>())
                            .unwrap_or(0);
                        if dst != 0 {
                            // Only export a handle if the DtoD copy succeeded —
                            // otherwise the receiver would import uninitialised memory.
                            if bound
                                .call_method1("_cuda_memcpy", (dst, ptr_val, size, 3u32))
                                .is_ok()
                            {
                                Some(dst)
                            } else {
                                let _ = bound.call_method1("_free_gpu_buf", (pool_counter,));
                                None
                            }
                        } else {
                            None
                        }
                    };
                    let _ = bound.call_method1("_set_cuda_device", (saved_dev,));
                    result
                }
            } else {
                // CPU source → GPU pool: use pinned DMA (existing path).
                bound
                    .call_method1("dma_copy", (ptr_val, size, pool_counter, !is_pinned))
                    .and_then(|r| r.extract::<u64>())
                    .ok()
            };

            if let Some(gpu_ptr) = gpu_ptr
                && let Ok(handle) = bound
                    .call_method1("_ipc_export", (gpu_ptr,))
                    .and_then(|r| r.extract::<Vec<u8>>())
                && handle.len() == 64
            {
                unsafe {
                    // Write IPC handle into DORADMA reserved area [32..96)
                    std::ptr::copy_nonoverlapping(handle.as_ptr(), shmem_ptr.add(32), 64);
                    // ipc_present flag at byte 24
                    std::ptr::write(shmem_ptr.add(24) as *mut u64, 1u64);
                }
                ipc_written = true;
            }
        }

        // A CUDA receiver's shmem is header-only and useless without the IPC
        // handle.  If GPU-pool setup failed (or the CUDA helpers were
        // unavailable), fail registration instead of returning a pool that
        // every later write/read would silently reject.  Reclaim the shmem
        // segment on the way out (it was created with owner=false).
        if receiver_is_cuda && !ipc_written {
            // The GPU pool buffer (and, on the transit path, the page-locked
            // host transit buffer) were allocated before the IPC export, which
            // failed.  Free them before bailing — otherwise they leak for the
            // life of the process since no PoolSlot was stored to track them.
            if let Ok(helpers) = get_cuda_helpers(py) {
                let bound = helpers.bind(py);
                let _ = bound.call_method1("_free_gpu_buf", (pool_counter,));
                if transit_ptr != 0 {
                    let _ = bound.call_method1("_free_transit", (transit_ptr,));
                }
            }
            shmem.set_owner(true);
            eyre::bail!(
                "[{}] register_memory_pool: failed to set up GPU pool buffer / IPC handle for CUDA receiver `{}`",
                self.node_id,
                tensor_device
            );
        }

        // Seqlock: increment gen to even (write-complete)
        unsafe {
            let gen_ptr = shmem_ptr.add(96) as *mut u64;
            let old_gen = std::ptr::read_volatile(gen_ptr);
            std::ptr::write_volatile(gen_ptr, old_gen + 1);
            std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
        }

        // Store shmem in pool (keep alive)
        {
            let mut pool = PINNED_POOL.lock().unwrap_or_else(|e| e.into_inner());
            pool.insert(
                pool_counter,
                PoolSlot {
                    _shmem: shmem,
                    base: shmem_ptr as u64,
                    size: total_size,
                    is_pinned,
                    transit_ptr,
                    pool_device,
                },
            );
        }

        let buffer_id = format!("pool_{}_{}", self.node_id, pool_counter);

        // Register with daemon for lifecycle tracking
        {
            let hlc = dora_node_api::dora_core::uhlc::HLC::default();
            let ts = hlc.new_timestamp();
            let mut params = dora_node_api::MetadataParameters::new();
            params.insert(
                "ptr".to_string(),
                dora_node_api::Parameter::Integer(ptr_val as i64),
            );
            params.insert(
                "size".to_string(),
                dora_node_api::Parameter::Integer(size as i64),
            );
            params.insert("dtype".to_string(), dora_node_api::Parameter::String(dtype));
            params.insert(
                "shape".to_string(),
                dora_node_api::Parameter::ListInt(shape_list),
            );
            params.insert(
                "shared_memory_name".to_string(),
                dora_node_api::Parameter::String(shmem_name),
            );
            params.insert(
                "is_pinned".to_string(),
                dora_node_api::Parameter::Bool(is_pinned),
            );
            params.insert(
                "pinned_type".to_string(),
                dora_node_api::Parameter::String(pinned_type.to_string()),
            );
            params.insert(
                "ipc_present".to_string(),
                dora_node_api::Parameter::Bool(ipc_written),
            );
            params.insert(
                "buffer_id".to_string(),
                dora_node_api::Parameter::String(buffer_id.clone()),
            );

            let meta = dora_node_api::Metadata::from_parameters(ts, params);
            if let Err(e) = self
                .node
                .get_mut()
                .register_pinned_memory(buffer_id.clone(), meta)
            {
                tracing::warn!("[{}] failed to register memory pool: {:#}", self.node_id, e);
            }
        }

        let buffer_id_array = arrow::array::StringArray::from(vec![buffer_id]);
        let buf_py: Py<PyAny> = buffer_id_array.to_data().to_pyarrow(py)?.unbind();
        Ok(buf_py)
    }

    /// Write tensor data to an existing memory pool.
    ///
    /// Overwrites the data region of a previously-registered pool without
    /// re-registering, enabling memory reuse across iterations.
    ///
    /// # Concurrency / safety
    ///
    /// **This is a non-blocking overwrite.** The writer must not call this
    /// while a receiver is consuming the previous tensor. Data-byte
    /// consistency relies entirely on callers honoring a **turn-based
    /// discipline**: wait for the receiver to signal completion (e.g. via
    /// a `next_require` round-trip) before writing the next frame.
    ///
    /// The seqlock at header offset 96 detects in-flight overwrites so the
    /// reader can retry, but it does **not** prevent the overwrite itself.
    /// A writer that ignores the turn-based contract will produce torn
    /// (partially updated) data at the consumer.
    ///
    /// The bundled `examples/memory-pool/` dataflows demonstrate correct
    /// turn-based usage: the sender writes, outputs the pool ID, and waits
    /// for the next input event before writing again.
    #[pyo3(signature = (memory_pool_id, tensor_info))]
    pub fn write_memory_pool(
        &self,
        memory_pool_id: Py<PyAny>,
        tensor_info: &Bound<'_, PyDict>,
        py: Python,
    ) -> eyre::Result<()> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        let ptr_val: u64 = tensor_info
            .get_item("ptr")?
            .ok_or_else(|| eyre::eyre!("missing ptr"))?
            .extract()?;
        let size: usize = tensor_info
            .get_item("size")?
            .ok_or_else(|| eyre::eyre!("missing size"))?
            .extract()?;
        let tensor_device: String = tensor_info
            .get_item("device")?
            .ok_or_else(|| eyre::eyre!("missing device"))?
            .extract()?;
        let is_cuda = tensor_device.starts_with("cuda");

        {
            let freed = FREED_POOL_IDS.lock().unwrap_or_else(|e| e.into_inner());
            if freed.contains(&buffer_id) {
                warn_missing_memory_pool(&self.node_id, "write", &buffer_id);
                return Ok(());
            }
        }

        // Auto-select pinning based on tensor size (25 MiB threshold).
        // Shared by cache-miss PoolSlot construction and slow-path dma_copy;
        // cache-hit reuses the slot's stored is_pinned.
        let auto_pin = should_pin(is_cuda, size);

        // Fast path: pool_ format -> DORADMA
        if buffer_id.starts_with("pool_") {
            // Extract counter from the last underscore segment — node_id
            // may legitimately contain underscores.
            if let Some((_, counter_str)) = buffer_id.rsplit_once('_')
                && let Ok(counter) = counter_str.parse::<u64>()
            {
                // Try PINNED_POOL cache first to avoid per-iteration mmap/munmap.
                // register_memory_pool already stored the Shmem here; taking it
                // prevents munmap, and storing it back keeps the mapping alive.
                let pool_slot = {
                    PINNED_POOL
                        .lock()
                        .unwrap_or_else(|e| e.into_inner())
                        .remove(&counter)
                };

                // Both cache-hit and cache-miss produce a PoolSlot that is
                // stored back into PINNED_POOL after the write — this keeps
                // the shmem mapping alive for the duration of the data copy.
                let (shmem_ptr, shmem_capacity, mut store_back, is_pinned) =
                    if let Some(mut slot_data) = pool_slot {
                        // Cache hit: reuse the persistent mapping (no mmap).
                        // Recompute is_pinned from the current tensor size
                        // so the auto-selection reflects each write's payload.
                        let cap = slot_data.size;
                        slot_data.is_pinned = auto_pin;
                        let pinned = auto_pin;
                        (slot_data.base as *mut u8, cap, Some(slot_data), pinned)
                    } else {
                        // Cache miss: open via ShmemConf, wrap immediately
                        // so the mapping stays alive until post-write re-insert.
                        let shmem_name = format!(
                            "dora_pool_{}_{}_{}",
                            self.dataflow_id, self.node_id, counter
                        );
                        match ShmemConf::new().os_id(&shmem_name).open() {
                            Ok(shmem) => {
                                let cap = shmem.len();
                                let base = shmem.as_ptr() as u64;
                                let slot = PoolSlot {
                                    _shmem: shmem,
                                    base,
                                    size: cap,
                                    is_pinned: auto_pin,
                                    transit_ptr: 0,
                                    pool_device: 0,
                                };
                                (base as *mut u8, cap, Some(slot), auto_pin)
                            }
                            Err(_) => (std::ptr::null_mut(), 0, None, false),
                        }
                    };

                if !shmem_ptr.is_null() {
                    // Guard against truncated segments before any
                    // pointer arithmetic (mirrors slow-path + read guards).
                    if shmem_capacity < DORADMA_HEADER_SIZE {
                        if let Some(slot_data) = store_back {
                            PINNED_POOL
                                .lock()
                                .unwrap_or_else(|e| e.into_inner())
                                .insert(counter, slot_data);
                        }
                        return Ok(());
                    }
                    let magic = unsafe { std::slice::from_raw_parts(shmem_ptr, 8) };
                    if magic == DORADMA_MAGIC {
                        let data_offset = unsafe { read_header_u64(shmem_ptr.add(16)) as usize };

                        // Check if this pool has GPU DMA path enabled
                        let ipc_present =
                            unsafe { std::ptr::read(shmem_ptr.add(24) as *const u64) };

                        // Validate write size against pool capacity.  The
                        // `size == 0` guard always applies.  For GPU-buffer pools
                        // (ipc_present == 1) the shmem data region is unused, so
                        // its capacity is irrelevant — the GPU-buffer helpers
                        // validate `size` against the actual GPU allocation.
                        if size == 0
                            || (ipc_present != 1
                                && size > shmem_capacity.saturating_sub(data_offset))
                        {
                            tracing::warn!(
                                "[{}] write_memory_pool: size {} exceeds available pool capacity (data_offset={}, total={}), operation aborted",
                                self.node_id,
                                size,
                                data_offset,
                                shmem_capacity
                            );
                            // Store back to PINNED_POOL to keep shmem alive
                            if let Some(slot_data) = store_back {
                                PINNED_POOL
                                    .lock()
                                    .unwrap_or_else(|e| e.into_inner())
                                    .insert(counter, slot_data);
                            }
                            return Ok(());
                        }

                        if ipc_present == 1 && !is_cuda {
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            // DMA: source CPU data -> GPU pool buffer via DMA engine.
                            // When is_pinned=false, dma_copy skips cudaHostRegister/
                            // cudaHostUnregister — pageable cudaMemcpy is faster for
                            // small tensors where pin overhead dominates.
                            if let Ok(helpers) = get_cuda_helpers(py) {
                                let bound = helpers.bind(py);
                                let _ = bound
                                    .call_method1("dma_copy", (ptr_val, size, counter, !is_pinned));
                            }
                            // Seqlock: end write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        } else if is_cuda {
                            // If the previous GPU copy failed, gen was left
                            // odd.  Restore even parity before beginning a
                            // new write so the begin/end increments don't
                            // invert the seqlock contract.
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let cur = std::ptr::read_volatile(gen_ptr);
                                if cur % 2 != 0 {
                                    std::ptr::write_volatile(gen_ptr, cur + 1);
                                    std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                                }
                            }
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            let write_result = if let Ok(helpers) = get_cuda_helpers(py) {
                                let bound = helpers.bind(py);
                                if ipc_present == 1 {
                                    // GPU pool: write to the GPU buffer.  Read the
                                    // transit info from the slot we already hold
                                    // (store_back) — re-querying PINNED_POOL here
                                    // would always miss, since the slot was removed
                                    // from the map at the top of the fast path.
                                    let transit =
                                        store_back.as_ref().map(|s| (s.transit_ptr, s.pool_device));
                                    if let Some((tp, pool_dev)) = transit
                                        && tp != 0
                                    {
                                        // Cross-device without P2P: stage through the
                                        // CPU page-locked transit buffer.
                                        let sender_dev = tensor_device
                                            .strip_prefix("cuda")
                                            .and_then(|d| d.strip_prefix(':'))
                                            .and_then(|d| d.parse::<i32>().ok())
                                            .unwrap_or(0);
                                        bound
                                            .call_method1(
                                                "_transit_copy_gpu_buf",
                                                (counter, ptr_val, sender_dev, tp, pool_dev, size),
                                            )
                                            .map(|_| ())
                                    } else {
                                        bound
                                            .call_method1(
                                                "_cuda_memcpy_gpu_buf",
                                                (counter, ptr_val, size),
                                            )
                                            .map(|_| ())
                                    }
                                } else {
                                    // CPU pool: copy GPU source → shmem via DtoH so the
                                    // receiver can read the data through /dev/shm.
                                    bound
                                        .call_method1(
                                            "_cuda_memcpy",
                                            (
                                                shmem_ptr as u64 + data_offset as u64,
                                                ptr_val,
                                                size,
                                                2u32,
                                            ),
                                        )
                                        .map(|_| ())
                                }
                            } else {
                                Ok(())
                            };

                            // Check copy result before advancing the seqlock.
                            // On failure, leave gen odd so the reader sees
                            // an incomplete write and falls back to the
                            // daemon path.  The next successful write will
                            // restore even parity before beginning.
                            // Re-insert the slot first so the pool survives
                            // for later frames.
                            if let Err(e) = write_result {
                                if let Some(slot_data) = store_back.take() {
                                    PINNED_POOL
                                        .lock()
                                        .unwrap_or_else(|e| e.into_inner())
                                        .insert(counter, slot_data);
                                }
                                return Err(eyre::eyre!(
                                    "[{}] write_memory_pool: GPU pool copy failed: {}",
                                    self.node_id,
                                    e
                                ));
                            }

                            // Seqlock: end write (gen → even, only on copy success)
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        } else {
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            unsafe {
                                std::ptr::copy_nonoverlapping(
                                    ptr_val as *const u8,
                                    shmem_ptr.add(data_offset),
                                    size,
                                );
                            }
                            // Seqlock: end write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        }

                        // Store back to PINNED_POOL to keep shmem alive
                        if let Some(slot_data) = store_back {
                            PINNED_POOL
                                .lock()
                                .unwrap_or_else(|e| e.into_inner())
                                .insert(counter, slot_data);
                        }

                        return Ok(());
                    }
                }
            }
        }

        // Slow path: query daemon for pool metadata
        match self
            .node
            .get_mut()
            .read_pinned_memory(buffer_id.clone(), false)
        {
            Ok(metadata) => {
                let shmem_name = metadata.parameters.get("shared_memory_name").and_then(|p| {
                    if let Parameter::String(s) = p {
                        Some(s.clone())
                    } else {
                        None
                    }
                });

                if let Some(ref name) = shmem_name
                    && let Ok(shmem) = ShmemConf::new().os_id(name).open()
                {
                    // Mirror fast-path guard: reject segments smaller
                    // than the header before any pointer arithmetic.
                    if shmem.len() < DORADMA_HEADER_SIZE {
                        return Ok(());
                    }
                    let shmem_ptr = shmem.as_ptr();

                    let magic = unsafe { std::slice::from_raw_parts(shmem_ptr, 8) };
                    if magic == DORADMA_MAGIC {
                        let data_offset = unsafe { read_header_u64(shmem_ptr.add(16)) as usize };

                        // Check if this pool has GPU DMA path enabled
                        let ipc_present =
                            unsafe { std::ptr::read(shmem_ptr.add(24) as *const u64) };

                        // Validate write size against pool capacity.  The
                        // `size == 0` guard always applies; the shmem-region
                        // capacity check is skipped for GPU-buffer pools
                        // (ipc_present == 1), which the GPU helpers validate.
                        let shmem_len = shmem.len();
                        if size == 0
                            || (ipc_present != 1 && size > shmem_len.saturating_sub(data_offset))
                        {
                            tracing::warn!(
                                "[{}] write_memory_pool (slow path): size {} exceeds available pool capacity (data_offset={}, total={}), operation aborted",
                                self.node_id,
                                size,
                                data_offset,
                                shmem_len
                            );
                            return Ok(());
                        }

                        if ipc_present == 1 && !is_cuda {
                            // Extract counter for the DMA slot from buffer_id.
                            let slow_counter = buffer_id
                                .rsplit_once('_')
                                .and_then(|(_, c)| c.parse::<u64>().ok());
                            // Restore even parity if the previous GPU copy
                            // failed (gen was left odd).  Without this, the
                            // begin/end increments invert the seqlock contract.
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let cur = std::ptr::read_volatile(gen_ptr);
                                if cur % 2 != 0 {
                                    std::ptr::write_volatile(gen_ptr, cur + 1);
                                    std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                                }
                            }
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            // Slow path: daemon-mediated fallback (rare).
                            // Respect the same 25 MiB auto-pin threshold as the
                            // fast path and register_memory_pool.  no_dma=true
                            // skips cudaHostRegister for small pageable tensors
                            // where pin overhead dominates DMA gain.
                            let slow_no_dma = !auto_pin;
                            if let (Ok(helpers), Some(c)) = (get_cuda_helpers(py), slow_counter) {
                                let bound = helpers.bind(py);
                                let _ =
                                    bound.call_method1("dma_copy", (ptr_val, size, c, slow_no_dma));
                            }
                            // Seqlock: end write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        } else if is_cuda {
                            // If the previous GPU copy failed, gen was left
                            // odd.  Restore even parity before beginning a
                            // new write so the begin/end increments don't
                            // invert the seqlock contract.
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let cur = std::ptr::read_volatile(gen_ptr);
                                if cur % 2 != 0 {
                                    std::ptr::write_volatile(gen_ptr, cur + 1);
                                    std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                                }
                            }
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            let write_result = if let Ok(helpers) = get_cuda_helpers(py) {
                                let bound = helpers.bind(py);
                                if ipc_present == 1 {
                                    // GPU pool: write to the GPU buffer.  Use the
                                    // transit path when the pool is on a different
                                    // device without P2P (e.g. RTX 5090).  This slow
                                    // path does not hold the slot, so PINNED_POOL is
                                    // the correct source for the transit info.
                                    if let Some((_, counter_str)) = buffer_id.rsplit_once('_')
                                        && let Ok(c) = counter_str.parse::<u64>()
                                    {
                                        let transit = {
                                            PINNED_POOL
                                                .lock()
                                                .unwrap_or_else(|e| e.into_inner())
                                                .get(&c)
                                                .map(|s| (s.transit_ptr, s.pool_device))
                                        };
                                        if let Some((tp, pool_dev)) = transit
                                            && tp != 0
                                        {
                                            let sender_dev = tensor_device
                                                .strip_prefix("cuda")
                                                .and_then(|d| d.strip_prefix(':'))
                                                .and_then(|d| d.parse::<i32>().ok())
                                                .unwrap_or(0);
                                            bound
                                                .call_method1(
                                                    "_transit_copy_gpu_buf",
                                                    (c, ptr_val, sender_dev, tp, pool_dev, size),
                                                )
                                                .map(|_| ())
                                        } else {
                                            bound
                                                .call_method1(
                                                    "_cuda_memcpy_gpu_buf",
                                                    (c, ptr_val, size),
                                                )
                                                .map(|_| ())
                                        }
                                    } else {
                                        Ok(())
                                    }
                                } else {
                                    // CPU pool: copy GPU source → shmem via DtoH so the
                                    // receiver can read the data through /dev/shm.
                                    bound
                                        .call_method1(
                                            "_cuda_memcpy",
                                            (
                                                shmem_ptr as u64 + data_offset as u64,
                                                ptr_val,
                                                size,
                                                2u32,
                                            ),
                                        )
                                        .map(|_| ())
                                }
                            } else {
                                Ok(())
                            };

                            // Check copy result before advancing the seqlock.
                            // On failure, leave gen odd so the reader falls
                            // back to the daemon path.  The next successful
                            // write will restore even parity before beginning.
                            if let Err(e) = write_result {
                                return Err(eyre::eyre!(
                                    "[{}] write_memory_pool (slow path): GPU pool copy failed: {}",
                                    self.node_id,
                                    e
                                ));
                            }

                            // Seqlock: end write (gen → even, only on copy success)
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        } else {
                            // Seqlock: begin write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                            unsafe {
                                std::ptr::copy_nonoverlapping(
                                    ptr_val as *const u8,
                                    shmem_ptr.add(data_offset),
                                    size,
                                );
                            }
                            // Seqlock: end write
                            unsafe {
                                let gen_ptr = shmem_ptr.add(96) as *mut u64;
                                let old_gen = std::ptr::read_volatile(gen_ptr);
                                std::ptr::write_volatile(gen_ptr, old_gen + 1);
                                std::sync::atomic::fence(std::sync::atomic::Ordering::Release);
                            }
                        }
                    }
                }
            }
            Err(_) => {
                warn_missing_memory_pool(&self.node_id, "write", &buffer_id);
            }
        }

        Ok(())
    }

    /// Read tensor info from an existing memory pool (zero-copy).
    ///
    /// Returns a `tensor_info` dict compatible with `tensor_from_info`.
    /// The returned tensor shares the underlying shared-memory mapping —
    /// no copy is made, so data bytes reflect whatever the writer has most
    /// recently stored.
    ///
    /// # Concurrency / safety
    ///
    /// **The returned tensor is a zero-copy view into shared memory.**
    /// Its data bytes can be overwritten at any time by a concurrent (or
    /// subsequent) [`write_memory_pool`] on the sender. The seqlock
    /// re-check at end-of-read detects whether an overwrite occurred
    /// mid-consumption, but it is the **caller's responsibility** to
    /// ensure the tensor is not used after the writer is allowed to write
    /// again.
    ///
    /// Correct consumers follow a **turn-based discipline**: read the
    /// pool, consume the tensor fully, then signal the sender (e.g. via
    /// the dataflow graph's `next_require` round-trip) that it is safe to
    /// write the next frame. The bundled `examples/memory-pool/` dataflows
    /// demonstrate this pattern.
    pub fn read_memory_pool(
        &self,
        memory_pool_id: Py<PyAny>,
        py: Python,
    ) -> eyre::Result<Py<PyAny>> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        // Fast path: DORADMA header read.
        if buffer_id.starts_with("pool_") {
            if let Some(result) = self.try_doradma_read(&buffer_id, py)? {
                return Ok(result);
            }
            tracing::debug!(
                "[{}] read_memory_pool: fast path returned None, falling back to daemon",
                self.node_id
            );
        }

        // Slow path: query daemon
        match self
            .node
            .get_mut()
            .read_pinned_memory(buffer_id.clone(), false)
        {
            Ok(metadata) => {
                let size = metadata
                    .parameters
                    .get("size")
                    .and_then(|p| {
                        if let Parameter::Integer(v) = p {
                            Some(*v)
                        } else {
                            None
                        }
                    })
                    .unwrap_or(0);
                let dtype = metadata
                    .parameters
                    .get("dtype")
                    .and_then(|p| {
                        if let Parameter::String(s) = p {
                            Some(s.clone())
                        } else {
                            None
                        }
                    })
                    .unwrap_or_default();
                let shape = metadata
                    .parameters
                    .get("shape")
                    .and_then(|p| {
                        if let Parameter::ListInt(v) = p {
                            Some(v.clone())
                        } else {
                            None
                        }
                    })
                    .unwrap_or_default();

                let pinned_type = metadata
                    .parameters
                    .get("pinned_type")
                    .and_then(|p| {
                        if let Parameter::String(s) = p {
                            Some(s.as_str())
                        } else {
                            None
                        }
                    })
                    .unwrap_or("cpu");

                // Resolve the actual data pointer from shared memory.
                // The `ptr` in the daemon metadata is the registering node's
                // process-local address — meaningless in a different process.
                // Open the shmem file and read the DORADMA header to obtain
                // a valid shmem-relative pointer.
                let shmem_name = metadata.parameters.get("shared_memory_name").and_then(|p| {
                    if let Parameter::String(s) = p {
                        Some(s.clone())
                    } else {
                        None
                    }
                });

                // Trusted ipc_present from daemon metadata — not the
                // world-writable shmem header.  When true, the shmem is
                // header-only and the GPU buffer is accessible via IPC import.
                let ipc_present_trusted = metadata.parameters.get("ipc_present").and_then(|p| {
                    if let Parameter::Bool(v) = p {
                        Some(*v)
                    } else {
                        None
                    }
                });
                let mut read_ptr: i64 = 0;
                // IPC handle bytes cached from the shmem header so they
                // survive the shmem borrow.
                let mut ipc_handle: Option<Vec<u8>> = None;
                if let Some(ref name) = shmem_name
                    && let Ok(shmem) = ShmemConf::new().os_id(name).open()
                {
                    // Mirror fast-path guard: reject segments smaller
                    // than the header before any pointer arithmetic.
                    if shmem.len() < DORADMA_HEADER_SIZE {
                        warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                        return Err(eyre::eyre!(
                            "memory pool {} segment too small ({})",
                            buffer_id,
                            shmem.len()
                        ));
                    }
                    let shmem_ptr = shmem.as_ptr();
                    let magic = unsafe { std::slice::from_raw_parts(shmem_ptr, 8) };
                    if magic == DORADMA_MAGIC {
                        let data_offset = unsafe { read_header_u64(shmem_ptr.add(16)) as usize };
                        // For GPU pools (ipc_present == 1) the shmem is
                        // header-only — skip the data-region capacity check.
                        if !matches!(ipc_present_trusted, Some(true))
                            && (data_offset > shmem.len()
                                || (size as usize) > shmem.len().saturating_sub(data_offset))
                        {
                            warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                            return Err(eyre::eyre!(
                                "memory pool {} header bounds exceeded: data_offset {} + size {} > shmem_len {}",
                                buffer_id,
                                data_offset,
                                size,
                                shmem.len()
                            ));
                        }
                        // Cache the IPC handle before the shmem borrow ends.
                        if matches!(ipc_present_trusted, Some(true)) {
                            ipc_handle = Some(
                                unsafe { std::slice::from_raw_parts(shmem_ptr.add(32), 64) }
                                    .to_vec(),
                            );
                        }
                        // Mirroring try_doradma_read: check cache first,
                        // so on a cache hit we return the cached mapping's
                        // pointer (not the fresh mmap, which will be dropped).
                        let mut cpu_cache =
                            RECV_CPU_SHMEM.lock().unwrap_or_else(|e| e.into_inner());
                        if let Some(cached) = cpu_cache.get(&buffer_id) {
                            read_ptr = (cached.base + data_offset as u64) as i64;
                        } else {
                            let base = shmem_ptr as u64;
                            read_ptr = (base + data_offset as u64) as i64;
                            cpu_cache.entry(buffer_id.clone()).or_insert(RecvCpuSlot {
                                _shmem: shmem,
                                base,
                            });
                        }
                    }
                }

                // GPU pool with IPC handle: re-import from the trusted
                // handle cached above.
                if matches!(ipc_present_trusted, Some(true))
                    && let Some(ref handle_bytes) = ipc_handle
                {
                    if let Ok(helpers) = get_cuda_helpers(py) {
                        let bound = helpers.bind(py);
                        let handle_py = PyBytes::new(py, handle_bytes);
                        let gpu_ptr: u64 = bound
                            .call_method1("_ipc_import", (handle_py,))
                            .and_then(|r| r.extract::<u64>())
                            .unwrap_or(0);
                        if gpu_ptr != 0 {
                            read_ptr = gpu_ptr as i64;
                            // Populate the trusted capacity cache so the
                            // fast path (`try_doradma_read`) can validate
                            // the world-writable shmem `size` against the
                            // daemon-trusted registered GPU buffer size.
                            GPU_BUF_SIZES
                                .lock()
                                .unwrap_or_else(|e| e.into_inner())
                                .insert(buffer_id.clone(), size as u64);
                        }
                    }
                }

                if read_ptr == 0 {
                    warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                    eyre::bail!("memory pool {} not found or has invalid pointer", buffer_id);
                }

                // Trusted ipc_present from the daemon gates device resolution.
                // For GPU pools the CUDA IPC re-import (above) provides a valid
                // device pointer; for CPU pools read_ptr is a host mmap.
                let device = if matches!(ipc_present_trusted, Some(true)) {
                    "cuda"
                } else if pinned_type.starts_with("cuda") {
                    // ipc_present_trusted is false but pinned_type=cuda:
                    // the fast path failed and the daemon cannot provide a
                    // GPU pointer — reject.
                    warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                    eyre::bail!(
                        "memory pool {}: daemon fallback cannot provide a CUDA pointer \
                         (fast path returned None); check that the pool was registered \
                         with the correct receiver device",
                        buffer_id,
                    );
                } else {
                    "cpu"
                };

                let dict = PyDict::new(py);
                dict.set_item("ptr", read_ptr)?;
                dict.set_item("size", size)?;
                dict.set_item("dtype", dtype)?;
                dict.set_item("shape", shape)?;
                dict.set_item("device", device)?;

                Ok(dict.into())
            }
            Err(e) => {
                warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                eyre::bail!("memory pool {} not found: {:?}", buffer_id, e);
            }
        }
    }

    /// Free a memory pool.
    #[pyo3(signature = (memory_pool_id))]
    pub fn free_memory_pool(&self, memory_pool_id: Py<PyAny>, py: Python) -> eyre::Result<()> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        match self.node.get_mut().free_pinned_memory(buffer_id.clone()) {
            Ok(_) => {}
            Err(_) => {
                warn_missing_memory_pool(&self.node_id, "release", &buffer_id);
            }
        }

        // Clean up sender-side pinned pool mapping (Shmem + CUDA host register).
        // Without this, each register->write->free cycle leaks one Shmem mapping
        // and one cudaHostRegister pinned region for the process lifetime.
        // PINNED_POOL is sender-side (per-process), so bare counter is sufficient.
        {
            let counter = buffer_id
                .strip_prefix("pool_")
                .and_then(|s| s.rsplit_once('_').map(|(_, c)| c))
                .and_then(|c| c.parse::<u64>().ok());
            if let Some(c) = counter
                && let Some(slot) = PINNED_POOL
                    .lock()
                    .unwrap_or_else(|e| e.into_inner())
                    .remove(&c)
                && let Ok(helpers) = get_cuda_helpers(py)
            {
                let bound = helpers.bind(py);
                let _ = bound.call_method1("_unregister_host", (slot.base,));
                let _ = bound.call_method1("_free_gpu_buf", (c,));
                if slot.transit_ptr != 0 {
                    let _ = bound.call_method1("_free_transit", (slot.transit_ptr,));
                }
            }
            // PoolSlot dropped here -> Shmem unmapped
        }

        // Clean up receiver-side caches so the shmem mappings are released.
        // Keyed by full buffer_id (namespaced) to correctly handle
        // multiple sender nodes with the same per-process counter.
        {
            // Close GPU IPC handle before dropping the cache entry.
            if let Some(slot) = RECV_GPU_VA
                .lock()
                .unwrap_or_else(|e| e.into_inner())
                .remove(&buffer_id)
            {
                if slot.gpu_buf != 0 {
                    if let Ok(helpers) = get_cuda_helpers(py) {
                        let bound = helpers.bind(py);
                        let _ = bound.call_method1("_ipc_close", (slot.gpu_buf,));
                    }
                } else if slot.gpu_va != 0 {
                    // Host-registered mapping (effective_as_cuda branch):
                    // must cudaHostUnregister before munmap.  _unregister_host
                    // requires the original host pointer (shmem base), not the
                    // device VA returned by cudaHostGetDevicePointer.
                    if let Ok(helpers) = get_cuda_helpers(py) {
                        let bound = helpers.bind(py);
                        let _ = bound.call_method1("_unregister_host", (slot.host_base,));
                    }
                }
                // slot._shmem drops here -> munmap
            }
        }
        RECV_CPU_SHMEM
            .lock()
            .unwrap_or_else(|e| e.into_inner())
            .remove(&buffer_id);
        GPU_BUF_SIZES
            .lock()
            .unwrap_or_else(|e| e.into_inner())
            .remove(&buffer_id);

        {
            let mut freed = FREED_POOL_IDS.lock().unwrap_or_else(|e| e.into_inner());
            tracing::debug!(
                "[{}] free_memory_pool: adding {} to FREED_POOL_IDS (set size={})",
                self.node_id,
                buffer_id,
                freed.len()
            );
            freed.insert(buffer_id);
        }

        Ok(())
    }
}

/// Stub for `send_output_raw` on Python < 3.11.
///
/// Raises `NotImplementedError` with an actionable install hint so callers get
/// clear feedback instead of a bare `AttributeError`.
#[cfg(not(Py_3_11))]
#[pymethods]
impl Node {
    #[pyo3(signature = (output_id, _data_length, _metadata=None))]
    pub fn send_output_raw(
        &self,
        output_id: String,
        _data_length: usize,
        _metadata: Option<Bound<'_, PyDict>>,
    ) -> PyResult<()> {
        Err(pyo3::exceptions::PyNotImplementedError::new_err(format!(
            "send_output_raw (output_id={output_id:?}) requires Python >= 3.11. \
             The zero-copy send path uses the stable Python buffer-protocol slots \
             which only became part of the stable C API in 3.11. \
             Upgrade Python or use send_output() instead (1 copy)."
        )))
    }
}

fn err_to_pyany(err: eyre::Report, gil: Python<'_>) -> Py<PyAny> {
    PyErr::from(err)
        .into_pyobject(gil)
        .unwrap_or_else(|infallible| match infallible {})
        .into_any()
        .unbind()
}

struct Events {
    inner: Arc<Mutex<EventsInner>>,
    _cleanup_handle: NodeCleanupHandle,
}

impl Events {
    fn recv(&self, timeout: Option<Duration>) -> Option<PyEvent> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => match timeout {
                Some(timeout) => events.recv_timeout(timeout).map(MergedEvent::Dora),
                None => events.recv().map(MergedEvent::Dora),
            },
            EventsInner::Merged(events) => futures::executor::block_on(events.next()),
        };
        event.map(|event| PyEvent { event })
    }

    fn try_recv(&self) -> Result<PyEvent, TryRecvError> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => events.try_recv().map(MergedEvent::Dora),
            EventsInner::Merged(_events) => {
                // try_recv is not supported on merged event streams;
                // return Empty (stream is still open, Closed would be wrong).
                return Err(TryRecvError::Empty);
            }
        };
        event.map(|event| PyEvent { event })
    }

    async fn recv_async_timeout(&self, timeout: Option<Duration>) -> Option<PyEvent> {
        let mut inner = self.inner.lock().await;
        let event = match &mut *inner {
            EventsInner::Dora(events) => match timeout {
                Some(timeout) => events
                    .recv_async_timeout(timeout)
                    .await
                    .map(MergedEvent::Dora),
                None => events.recv_async().await.map(MergedEvent::Dora),
            },
            EventsInner::Merged(events) => events.next().await,
        };
        event.map(|event| PyEvent { event })
    }

    fn drain(&self) -> Option<Vec<PyEvent>> {
        let mut inner = self.inner.blocking_lock();
        match &mut *inner {
            EventsInner::Dora(events) => events.drain().map(|items| {
                items
                    .into_iter()
                    .map(MergedEvent::Dora)
                    .map(|event| PyEvent { event })
                    .collect()
            }),
            EventsInner::Merged(_events) => {
                // drain is not supported on merged event streams; return
                // empty list (stream is still open, None would signal closed).
                Some(vec![])
            }
        }
    }

    fn is_empty(&self) -> bool {
        let inner = self.inner.blocking_lock();
        match &*inner {
            EventsInner::Dora(events) => events.is_empty(),
            EventsInner::Merged(_events) => {
                // Cannot determine emptiness of a merged stream; conservatively
                // return false so callers do not skip a recv() call.
                false
            }
        }
    }
}

#[allow(clippy::large_enum_variant)]
enum EventsInner {
    Dora(EventStream),
    Merged(Box<dyn Stream<Item = MergedEvent<Py<PyAny>>> + Unpin + Send + Sync>),
}

impl<'a> MergeExternalSend<'a, Py<PyAny>> for EventsInner {
    type Item = MergedEvent<Py<PyAny>>;

    fn merge_external_send(
        self,
        external_events: impl Stream<Item = Py<PyAny>> + Unpin + Send + Sync + 'a,
    ) -> Box<dyn Stream<Item = Self::Item> + Unpin + Send + Sync + 'a> {
        match self {
            EventsInner::Dora(events) => events.merge_external_send(external_events),
            EventsInner::Merged(events) => {
                let merged = events.merge_external_send(external_events);
                Box::new(merged.map(|event| match event {
                    MergedEvent::Dora(e) => MergedEvent::Dora(e),
                    MergedEvent::External(e) => MergedEvent::External(e.flatten()),
                }))
            }
        }
    }
}

impl Node {
    pub fn id(&self) -> String {
        self.node_id.to_string()
    }

    /// DORADMA fast path for read_memory_pool: reads metadata directly from
    /// the shmem header, bypassing the daemon for zero-copy metadata retrieval.
    ///
    /// Buffer ID format: `"pool_{node_id}_{counter}"` →
    /// shmem name: `"dora_pool_{dataflow_id}_{node_id}_{counter}"`.
    ///
    /// # Synchronization model
    ///
    /// The seqlock (write_gen at header offset 96) guards **data-byte**
    /// consistency across `write_memory_pool` overwrites — the end-of-read
    /// generation re-check detects if a write occurred mid-read.  Header
    /// fields (json_len, data_offset) are written once at registration and
    /// never change, so they are not subject to torn-read risk.
    ///
    /// The seqlock does NOT protect the tensor data bytes from being
    /// overwritten while a consumer is iterating the zero-copy tensor.
    /// Callers must enforce a **turn-based** discipline: the writer must
    /// not begin a new `write_memory_pool` until the receiver has finished
    /// consuming the previous tensor. The example dataflow enforces this
    /// via `next_require` round-trip signaling.
    ///
    /// Returns `Ok(Some(tensor_info_dict))` on success, `Ok(None)` to fall back to daemon.
    fn try_doradma_read(&self, buffer_id: &str, py: Python<'_>) -> eyre::Result<Option<Py<PyAny>>> {
        // Format: "pool_{node_id}_{counter}".
        // Use rsplit to extract the counter from the end — the node_id
        // portion may itself contain underscores (legal in dora node ids).
        let counter: u64 = match buffer_id.rsplit_once('_') {
            Some((_, c)) => match c.parse() {
                Ok(c) => c,
                Err(_) => return Ok(None),
            },
            None => return Ok(None),
        };
        let pool_node_id = buffer_id
            .strip_prefix("pool_")
            .and_then(|s| s.strip_suffix(&format!("_{counter}")))
            .unwrap_or("");

        // Check freed tracking -> if this buffer was freed, fall back to daemon
        {
            let freed = FREED_POOL_IDS.lock().unwrap_or_else(|e| e.into_inner());
            if freed.contains(buffer_id) {
                tracing::debug!(
                    "[{}] try_doradma_read: buffer {} is freed, fallback to daemon",
                    self.node_id,
                    buffer_id
                );
                return Ok(None);
            }
        }

        let shmem_name = format!(
            "dora_pool_{}_{}_{}",
            self.dataflow_id, pool_node_id, counter
        );

        // Open shared memory
        let shmem = match ShmemConf::new().os_id(&shmem_name).open() {
            Ok(s) => s,
            Err(_) => return Ok(None),
        };

        let shmem_ptr = shmem.as_ptr();
        let shmem_size = shmem.len();

        // Reject truncated segments: need at least DORADMA_HEADER_SIZE bytes for the header
        if shmem_size < DORADMA_HEADER_SIZE {
            tracing::warn!(
                "[{}] try_doradma_read: shmem size {} < DORADMA_HEADER_SIZE {}, rejecting",
                self.node_id,
                shmem_size,
                DORADMA_HEADER_SIZE,
            );
            return Ok(None);
        }

        // Verify DORADMA magic header

        unsafe {
            let magic = std::slice::from_raw_parts(shmem_ptr, 8);
            if magic != DORADMA_MAGIC {
                return Ok(None);
            }
        }

        // Read header: [magic:8][json_len:8][data_offset:8][reserved:232]
        let json_len = unsafe { read_header_u64(shmem_ptr.add(8)) as usize };
        let data_offset = unsafe { read_header_u64(shmem_ptr.add(16)) as usize };

        // Validate JSON length fits within the segment
        if json_len > shmem_size.saturating_sub(DORADMA_HEADER_SIZE) {
            tracing::warn!(
                "[{}] try_doradma_read: json_len {} exceeds shmem bounds (size={}, header={})",
                self.node_id,
                json_len,
                shmem_size,
                DORADMA_HEADER_SIZE,
            );
            return Ok(None);
        }

        // Read JSON metadata from header
        let json_slice =
            unsafe { std::slice::from_raw_parts(shmem_ptr.add(DORADMA_HEADER_SIZE), json_len) };
        let json_str = match std::str::from_utf8(json_slice) {
            Ok(s) => s,
            Err(_) => return Ok(None),
        };

        // Parse JSON to Python dict
        let metadata_dict: Bound<'_, PyDict> = match py.import("json") {
            Ok(m) => match m.call_method1("loads", (json_str,)) {
                Ok(v) => match v.downcast_into::<PyDict>() {
                    Ok(d) => d,
                    Err(_) => return Ok(None),
                },
                Err(_) => return Ok(None),
            },
            Err(_) => return Ok(None),
        };

        let size: usize = match metadata_dict.get_item("size") {
            Ok(Some(v)) => v.extract().unwrap_or(0),
            _ => 0,
        };
        if size == 0 {
            return Ok(None);
        }

        // Check if this pool uses GPU DMA (IPC handle in header).
        // Reading ipc_present early lets us skip the shmem data-region
        // size check for GPU-buffer pools (receiver_is_cuda registrations
        // allocate header-only shmem).
        let ipc_present = unsafe { std::ptr::read(shmem_ptr.add(24) as *const u64) };

        // Verify data_offset + size fits within shared memory segment.
        // GPU-buffer reads (ipc_present == 1) don't access the shmem data
        // region, so the size check is only required for CPU-receiver paths.
        if ipc_present != 1 {
            // Use saturating operations to guard against corrupted/hostile
            // headers with a near-usize::MAX data_offset (overflow-safe,
            // matching the write-path checks).
            if data_offset > shmem_size || size > shmem_size.saturating_sub(data_offset) {
                tracing::warn!(
                    "[{}] try_doradma_read: data_offset {} + size {} exceeds shmem_size {}",
                    self.node_id,
                    data_offset,
                    size,
                    shmem_size,
                );
                return Ok(None);
            }
        }

        // Auto-detect read path from pinned_type
        let pinned_type: Option<String> = metadata_dict
            .get_item("pinned_type")
            .ok()
            .flatten()
            .and_then(|v| v.extract::<String>().ok());

        let effective_as_cuda = ipc_present == 1 || pinned_type.as_deref() != Some("cpu");

        // Seqlock: read generation, validate stable after data access
        let read_gen = unsafe { std::ptr::read_volatile(shmem_ptr.add(96) as *const u64) };
        if read_gen % 2 != 0 {
            // Writer is in progress — retry (caller falls back to daemon)
            return Ok(None);
        }
        std::sync::atomic::fence(std::sync::atomic::Ordering::Acquire);

        let read_ptr: u64;

        if ipc_present == 1 {
            // GPU DMA pool: import IPC handle once, cache GPU buffer ptr
            read_ptr = {
                let cache = RECV_GPU_VA.lock().unwrap_or_else(|e| e.into_inner());
                match cache.get(buffer_id) {
                    Some(slot_data) if slot_data.gpu_buf != 0 => {
                        // Validate size against the GPU buffer's registered
                        // capacity.  GPU_BUF_SIZES (populated from daemon
                        // metadata) is authoritative; gpu_buf_size (populated
                        // from shmem at first import) is the baseline.
                        // If size exceeds the trusted capacity, fall back to
                        // the daemon so the read is re-validated.
                        let capped = {
                            let trusted = GPU_BUF_SIZES
                                .lock()
                                .unwrap_or_else(|e| e.into_inner());
                            trusted
                                .get(buffer_id)
                                .copied()
                                .or(Some(slot_data.gpu_buf_size))
                        };
                        if let Some(max_size) = capped {
                            if max_size > 0 && (size as u64) > max_size {
                                return Ok(None);
                            }
                        }
                        slot_data.gpu_buf
                    }
                    _ => {
                        drop(cache);
                        let handle_bytes =
                            unsafe { std::slice::from_raw_parts(shmem_ptr.add(32), 64) };
                        let helpers = get_cuda_helpers(py)
                            .map_err(|e| eyre::eyre!("get_cuda_helpers: {}", e))?;
                        let bound = helpers.bind(py);
                        // No explicit P2P enablement needed here: _ipc_import
                        // opens the handle with cudaIpcMemLazyEnablePeerAccess,
                        // which lazily routes cross-device access through
                        // NVLink/PCIe-P2P on first touch.  The receiver also
                        // does not know the sender's device index to scope a
                        // pairwise enable.
                        let handle_py = PyBytes::new(py, handle_bytes);
                        let gpu_ptr: u64 = bound
                            .call_method1("_ipc_import", (handle_py,))
                            .map_err(|e| eyre::eyre!("_ipc_import: {}", e))?
                            .extract()
                            .map_err(|e| eyre::eyre!("extract gpu_ptr: {}", e))?;
                        let mut cache = RECV_GPU_VA.lock().unwrap_or_else(|e| e.into_inner());
                        cache.insert(
                            buffer_id.to_string(),
                            RecvGpuSlot {
                                _shmem: shmem,
                                gpu_va: 0,
                                gpu_buf: gpu_ptr,
                                host_base: shmem_ptr as u64,
                                // Baseline size from shmem — the daemon
                                // fallback will overwrite GPU_BUF_SIZES
                                // with the trusted value when it runs.
                                gpu_buf_size: size as u64,
                            },
                        );
                        gpu_ptr
                    }
                }
            };
        } else if effective_as_cuda {
            read_ptr = {
                let cache = RECV_GPU_VA.lock().unwrap_or_else(|e| e.into_inner());
                match cache.get(buffer_id) {
                    Some(slot_data) => {
                        // GPU VA is stable across data overwrites;
                        // cache is keyed by full buffer_id (namespaced).
                        slot_data.gpu_va + data_offset as u64
                    }
                    None => {
                        drop(cache);
                        let helpers = get_cuda_helpers(py)
                            .map_err(|e| eyre::eyre!("get_cuda_helpers: {}", e))?;
                        let bound = helpers.bind(py);
                        bound
                            .call_method1("_register_host", (shmem_ptr as u64, shmem_size))
                            .map_err(|e| eyre::eyre!("_register_host: {}", e))?;
                        let va: u64 = bound
                            .call_method1("_get_device_ptr", (shmem_ptr as u64,))
                            .map_err(|e| eyre::eyre!("_get_device_ptr: {}", e))?
                            .extract()
                            .map_err(|e| eyre::eyre!("extract gpu_va: {}", e))?;
                        let mut cache = RECV_GPU_VA.lock().unwrap_or_else(|e| e.into_inner());
                        cache.insert(
                            buffer_id.to_string(),
                            RecvGpuSlot {
                                _shmem: shmem,
                                gpu_va: va,
                                gpu_buf: 0,
                                host_base: shmem_ptr as u64,
                                gpu_buf_size: 0, // CPU memory, no GPU buffer
                            },
                        );
                        va + data_offset as u64
                    }
                }
            };
        } else {
            // On the first read the fresh mapping is cached; on subsequent
            // reads the fresh mapping is dropped and the returned pointer
            // must use the cached mapping's base (a different mmap address).
            let mut cpu_cache = RECV_CPU_SHMEM.lock().unwrap_or_else(|e| e.into_inner());
            read_ptr = match cpu_cache.get(buffer_id) {
                Some(cached) => cached.base + data_offset as u64,
                None => {
                    let base = shmem_ptr as u64;
                    cpu_cache.insert(
                        buffer_id.to_string(),
                        RecvCpuSlot {
                            _shmem: shmem,
                            base,
                        },
                    );
                    base + data_offset as u64
                }
            };
        }

        // Seqlock: re-read generation — mismatch means data changed during read
        let read_gen2 = unsafe { std::ptr::read_volatile(shmem_ptr.add(96) as *const u64) };
        if read_gen2 != read_gen {
            return Ok(None);
        }

        // Build tensor_info dict
        let dtype: String = metadata_dict
            .get_item("dtype")
            .ok()
            .flatten()
            .and_then(|v| v.extract::<String>().ok())
            .unwrap_or_default();
        let shape: Vec<i64> = metadata_dict
            .get_item("shape")
            .ok()
            .flatten()
            .and_then(|v| v.extract::<Vec<i64>>().ok())
            .unwrap_or_default();
        let device = if effective_as_cuda { "cuda" } else { "cpu" };

        let dict = PyDict::new(py);
        dict.set_item("ptr", read_ptr as i64)?;
        dict.set_item("size", size)?;
        dict.set_item("dtype", dtype)?;
        dict.set_item("shape", shape)?;
        dict.set_item("device", device)?;

        // A successful fast-path read means the pool is alive.  Clear
        // any stale tombstone so that the fast path re-engages after a
        // sender restart re-creates the same buffer_id (FREED_POOL_IDS
        // is per-process and free_memory_pool inserts there).
        {
            FREED_POOL_IDS
                .lock()
                .unwrap_or_else(|e| e.into_inner())
                .remove(buffer_id);
        }

        Ok(Some(dict.into()))
    }
}

/// Start a runtime for Operators
///
/// :rtype: None
#[pyfunction]
pub fn start_runtime() -> eyre::Result<()> {
    dora_runtime::main().wrap_err("Dora Runtime raised an error.")
}

/// Build a Dataflow, exactly the same way as `dora build` command line tool.
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type coordinator_addr: str, optional
/// :type coordinator_port: int, optional
/// :type force_local: bool, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, coordinator_addr=None, coordinator_port=None, force_local=false))]
pub fn build(
    dataflow_path: String,
    uv: Option<bool>,
    coordinator_addr: Option<String>,
    coordinator_port: Option<u16>,
    force_local: bool,
) -> eyre::Result<()> {
    dora_cli::build(dora_cli::BuildConfig::from_str_args(
        dataflow_path,
        uv,
        coordinator_addr,
        coordinator_port,
        force_local,
    )?)
}

/// Run a Dataflow, exactly the same way as `dora run` command line tool.
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type stop_after: float, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, stop_after=None))]
pub fn run(dataflow_path: String, uv: Option<bool>, stop_after: Option<f64>) -> eyre::Result<()> {
    use dora_cli::Executable;

    let stop_after_duration = stop_after.map(std::time::Duration::from_secs_f64);
    let mut cmd = dora_cli::RunCommand::new(dataflow_path);
    if let Some(uv) = uv {
        cmd.uv = uv;
    }
    if let Some(duration) = stop_after_duration {
        cmd.stop_after = Some(duration);
    }
    cmd.execute()
}

#[pymodule]
fn dora(_py: Python, m: Bound<'_, PyModule>) -> PyResult<()> {
    dora_ros2_bridge_python::create_dora_ros2_bridge_module(&m)?;

    m.add_function(wrap_pyfunction!(start_runtime, &m)?)?;
    m.add_function(wrap_pyfunction!(run, &m)?)?;
    m.add_function(wrap_pyfunction!(build, &m)?)?;
    m.add_class::<Node>()?;
    m.setattr("__version__", env!("CARGO_PKG_VERSION"))?;
    m.setattr("__author__", "Dora-rs Authors")?;

    Ok(())
}
